(6, 9, 6, '2026-05-07 07:55:49', '2026-05-07 07:55:49', 40.00, 5, 2, 'graded', '2026-05-07 07:55:49', '{\"summary\": \"The employee demonstrated partial understanding of bomb threat response protocols, correctly identifying the timing for evacuation and the importance of following specialist guidance. However, there were significant gaps in initial threat verification, notification procedures, and handling of suspicious objects.\", \"strengths\": [\"Understands that evacuation should be directed by incident command based on threat severity and location\", \"Recognizes the importance of following directions and technical guidance from specialists during the incident\"], \"weaknesses\": [\"Did not identify verifying the source of the bomb threat as the first action\", \"Failed to notify relevant specialized authorities immediately after verification\", \"Incorrectly instructed security personnel to ignore suspicious objects rather than isolate the area without moving them\"], \"recommendations\": [\"Review procedures for initial bomb threat verification and information gathering\", \"Emphasize the importance of promptly notifying specialized authorities through approved emergency channels\", \"Train on proper handling of suspicious objects, focusing on area isolation without disturbance\", \"Reinforce the sequence of actions to ensure safety and compliance with incident command directives\"]}'),
(7, 9, 6, '2026-05-07 07:55:49', '2026-05-07 07:55:49', 40.00, 5, 2, 'graded', '2026-05-07 07:55:49', '{\"summary\": \"AI feedback could not be generated.\", \"strengths\": [], \"weaknesses\": [], \"recommendations\": [\"Review the training procedure and try again.\"]}'),
(8, 10, 6, '2026-05-07 08:12:24', '2026-05-07 08:12:24', 40.00, 5, 2, 'graded', '2026-05-07 08:12:24', '{\"summary\": \"The employee demonstrated a basic understanding of the initial response to a missing child incident but showed significant gaps in specific protocol knowledge related to their role and proper escalation procedures.\", \"strengths\": [\"Correctly identified the first action security operations must take upon receiving a missing child report.\", \"Understood the importance of expanding the search outside the facility if the child is not found inside.\"], \"weaknesses\": [\"Incorrectly identified when female security staff are specifically requested to assist.\", \"Failed to recognize the correct procedure when the child is found with a suspicious person.\", \"Did not select the proper method to alert staff about the missing child (Code Pink announcement).\"], \"recommendations\": [\"Review the specific roles and responsibilities of female security staff during a Code Pink event.\", \"Reinforce procedures for handling suspicious persons found with the missing child.\", \"Emphasize the importance and protocol of announcing Code Pink via the overhead speaker system to alert all staff.\", \"Engage in additional scenario-based training to improve response accuracy and confidence.\"]}'),
(9, 10, 6, '2026-05-07 08:12:24', '2026-05-07 08:12:24', 40.00, 5, 2, 'graded', '2026-05-07 08:12:24', '{\"summary\": \"AI feedback could not be generated.\", \"strengths\": [], \"weaknesses\": [], \"recommendations\": [\"Review the training procedure and try again.\"]}'),
(10, 11, 6, '2026-05-07 08:17:42', '2026-05-07 08:17:42', 40.00, 5, 2, 'graded', '2026-05-07 08:17:42', '{\"summary\": \"AI feedback could not be generated.\", \"strengths\": [], \"weaknesses\": [], \"recommendations\": [\"Review the training procedure and try again.\"]}'),
