(12, 12, 6, '2026-05-07 08:36:57', '2026-05-07 08:36:57', 40.00, 5, 2, 'graded', '2026-05-07 08:36:57', '{\"summary\": \"AI feedback could not be generated.\", \"strengths\": [], \"weaknesses\": [], \"recommendations\": [\"Review the training procedure and try again.\"]}'),
(13, 12, 6, '2026-05-07 08:36:57', '2026-05-07 08:36:57', 40.00, 5, 2, 'graded', '2026-05-07 08:36:57', '{\"summary\": \"AI feedback could not be generated.\", \"strengths\": [], \"weaknesses\": [], \"recommendations\": [\"Review the training procedure and try again.\"]}'),
(14, 13, 6, '2026-05-07 08:43:17', '2026-05-07 08:43:17', 40.00, 5, 2, 'graded', '2026-05-07 08:43:17', '{\"summary\": \"AI feedback could not be generated.\", \"strengths\": [], \"weaknesses\": [], \"recommendations\": [\"Review the training procedure and try again.\"]}'),
(15, 13, 6, '2026-05-07 08:43:17', '2026-05-07 08:43:17', 40.00, 5, 2, 'graded', '2026-05-07 08:43:17', '{\"summary\": \"The employee demonstrated partial understanding of the hazardous material spill response protocol, correctly identifying key safety and reporting procedures but missing critical initial verification and communication steps.\", \"strengths\": [\"Correctly identified the need for specialists to wear designated protective equipment before accessing the incident site.\", \"Accurately recognized the importance of preparing and submitting a joint incident report after managing the spill.\"], \"weaknesses\": [\"Failed to prioritize rapid verification of the spill report source and exact location as the first step.\", \"Incorrectly handled the announcement procedure for Code Orange within the facility.\", \"Misidentified the appropriate communication targets, selecting hospital patients and visitors instead of Civil Defense and Hazmat Response Team.\"], \"recommendations\": [\"Review the initial response protocol emphasizing verification of incident reports before further action.\", \"Reinforce proper communication channels and announcement procedures for Code Orange alerts.\", \"Train on the roles and responsibilities of Facility Leadership in coordinating with Civil Defense and Hazmat teams during hazardous material incidents.\"]}'),
(16, 14, 6, '2026-05-07 08:55:41', '2026-05-07 08:55:41', 40.00, 5, 2, 'graded', '2026-05-07 08:55:42', '{\"summary\": \"The trainee demonstrated partial understanding of the elevator failure response protocol, correctly identifying the need to inform the Safety & Security Manager and to switch off and label the elevator during maintenance. However, they missed critical initial and follow-up steps such as recording trapped individuals\' details and dispatching technicians promptly.\", \"strengths\": [\"Correctly identified the need to inform the Safety & Security Manager immediately.\", \"Understood the importance of switching off the elevator and labeling it as \'out of service\' during maintenance.\"], \"weaknesses\": [\"Failed to record essential information about trapped individuals at the onset.\", \"Did not prioritize dispatching technicians to inspect and resolve the issue promptly.\", \"Incorrect follow-up actions after the issue resolution, such as calling the engineer instead of reporting and recording findings.\"], \"recommendations\": [\"Emphasize the importance of gathering and recording detailed information about trapped individuals immediately.\", \"Train on the protocol to dispatch technicians quickly to assess and resolve elevator failures.\", \"Reinforce the need to document and report all findings after the incident is resolved to ensure accountability and future prevention.\"]}'),
(17, 14, 6, '2026-05-07 08:55:42', '2026-05-07 08:55:42', 40.00, 5, 2, 'graded', '2026-05-07 08:55:42', '{\"summary\": \"The trainee demonstrated partial understanding of the elevator failure protocol, correctly identifying the need to inform the Safety & Security Manager and to switch off and label the elevator during maintenance. However, they missed critical initial and follow-up steps such as recording trapped individuals\' details, dispatching technicians promptly, and reporting after resolution.\", \"strengths\": [\"Correctly identified the need to inform the Safety & Security Manager immediately.\", \"Understood the importance of switching off and labeling the elevator during maintenance.\"], \"weaknesses\": [\"Failed to record essential information about trapped individuals at the outset.\", \"Did not prioritize dispatching technicians to inspect and resolve the issue promptly.\", \"Did not report and record findings after the issue was resolved.\"], \"recommendations\": [\"Emphasize the importance of gathering and recording detailed information about trapped individuals immediately.\", \"Train to prioritize dispatching technical support quickly to assess and resolve elevator failures.\", \"Reinforce the protocol for reporting and documenting the incident after resolution to ensure accountability and follow-up.\"]}'),
(18, 15, 6, '2026-05-07 11:20:26', '2026-05-07 11:20:26', 40.00, 5, 2, 'graded', '2026-05-07 11:20:26', '{\"summary\": \"The trainee demonstrated partial understanding of crowd gathering control and management, correctly answering questions on maintaining calm behavior and deploying sufficient security personnel, but failed on key procedural steps such as initial crowd prevention, security accompaniment, and post-event monitoring.\", \"strengths\": [\"Understands the importance of calm and patient interaction with crowds.\", \"Knows to deploy sufficient security personnel and establish security perimeters.\"], \"weaknesses\": [\"Incorrectly prioritizes calling media over preventing unauthorized crowd entry.\", \"Fails to assign security personnel to accompany individuals allowed entry.\", \"Stops monitoring too early after crowd dispersal.\"], \"recommendations\": [\"Emphasize the critical first step of preventing unauthorized crowd entry to protect facility safety.\", \"Train on the importance of security accompaniment for individuals entering through the crowd to ensure safety.\", \"Reinforce the need for continuous monitoring until the crowd has completely dispersed from the area.\"]}'),
(19, 15, 6, '2026-05-07 11:20:26', '2026-05-07 11:20:26', 40.00, 5, 2, 'graded', '2026-05-07 11:20:26', '{\"summary\": \"The trainee demonstrated partial understanding of crowd control and management, correctly answering questions on security personnel behavior and deployment but failing on initial crowd prevention, escorting individuals, and post-event monitoring.\", \"strengths\": [\"Understands the importance of calm and patient behavior by security personnel.\", \"Recognizes the need for sufficient security personnel deployment to manage crowds.\"], \"weaknesses\": [\"Incorrectly prioritizes calling media over preventing unauthorized crowd entry.\", \"Fails to assign security personnel to accompany individuals allowed entry.\", \"Stops monitoring the crowd prematurely after dispersal begins.\"], \"recommendations\": [\"Emphasize the critical first step of preventing unauthorized crowd entry to protect facility safety.\", \"Train on the importance of security accompaniment for individuals entering through crowds to ensure their safety.\", \"Reinforce the need for continuous monitoring until the crowd fully disperses to avoid resurgence or security breaches.\"]}'),
(20, 16, 6, '2026-05-07 11:32:54', '2026-05-07 11:32:54', 20.00, 5, 1, 'graded', '2026-05-07 11:32:54', '{\"summary\": \"The trainee demonstrated limited knowledge in external disaster response activation and coordination, scoring 20%.\", \"strengths\": [\"Correctly identified the need for security personnel to implement PPE measures and follow Hazmat team instructions during biological, chemical, or radiological threats.\"], \"weaknesses\": [\"Incorrectly identified the first step in notifying hospital personnel about Code Yellow activation.\", \"Failed to recognize the importance of activating the facility external disaster emergency plan after announcing Code Yellow.\", \"Did not correctly identify key departments for coordination to raise readiness and preparedness.\", \"Misunderstood the conditions for escalating from Code Yellow to Code Red.\"], \"recommendations\": [\"Review hospital protocols for Code Yellow activation and notification procedures.\", \"Study the steps involved in activating and managing the hospital\'s external disaster emergency plan.\", \"Familiarize with the roles of various departments and units in disaster response coordination.\", \"Understand criteria for escalation from Code Yellow to Code Red during external disasters.\"]}'),
(21, 16, 6, '2026-05-07 11:32:55', '2026-05-07 11:32:55', 20.00, 5, 1, 'graded', '2026-05-07 11:32:55', '{\"summary\": \"The trainee demonstrated limited knowledge in the activation and coordination of hospital external disaster response, correctly answering only 1 out of 5 questions.\", \"strengths\": [\"Understands the importance of PPE and Hazmat team instructions during biological, chemical, or radiological threats.\"], \"weaknesses\": [\"Incorrectly identified the first step in notifying personnel about Code Yellow activation.\", \"Failed to recognize the need to activate the external disaster emergency plan after Code Yellow announcement.\", \"Did not identify the correct departments to coordinate with for security readiness.\", \"Misunderstood the conditions for escalating from Code Yellow to Code Red.\"], \"recommendations\": [\"Review hospital protocols for Code Yellow activation and notification procedures.\", \"Study the steps for activating the external disaster emergency plan and internal preparedness.\", \"Familiarize with key departments involved in disaster response coordination, especially ambulance command, emergency departments, and planning units.\", \"Understand escalation criteria from Code Yellow to Code Red during disaster responses.\"]}'),
(22, 17, 6, '2026-05-07 11:45:01', '2026-05-07 11:45:01', 33.33, 3, 1, 'graded', '2026-05-07 11:45:01', '{\"summary\": \"The security team demonstrated partial understanding of hazardous material spill response, correctly identifying the initial verification step but failing to properly announce Code Orange and implement safety measures.\", \"strengths\": [\"Correctly identified the need to rapidly verify the source and location of the chemical spill report.\"], \"weaknesses\": [\"Did not announce Code Orange properly over the overhead speaker system and failed to send wireless alerts to security teams.\", \"Failed to follow proper safety protocols by remaining in the affected area without appropriate protective equipment.\"], \"recommendations\": [\"Train security personnel to announce Code Orange multiple times over the overhead system and send wireless alerts to all relevant teams.\", \"Emphasize the importance of using personal protective equipment and rotating staff to avoid prolonged exposure to hazardous materials.\", \"Conduct drills focusing on communication protocols and safety measures during hazardous material incidents.\"]}'),
(23, 17, 6, '2026-05-07 11:45:01', '2026-05-07 11:45:01', 33.33, 3, 1, 'graded', '2026-05-07 11:45:01', '{\"summary\": \"The security team demonstrated partial understanding of the hazardous material spill response, correctly identifying the initial verification step but failing to properly announce the Code Orange alert and implement safety measures at the spill site.\", \"strengths\": [\"Correctly identified the need to rapidly verify the source and location of the chemical spill report.\"], \"weaknesses\": [\"Did not announce Code Orange alert appropriately over the overhead speaker system and to all relevant teams.\", \"Failed to apply proper safety measures such as using personal protective equipment and avoiding prolonged exposure at the spill site.\"], \"recommendations\": [\"Train security personnel to announce Code Orange alerts multiple times over the overhead system and send wireless signals to all emergency teams.\", \"Emphasize the importance of personal protective equipment and safe practices when securing hazardous spill sites.\", \"Conduct drills focusing on communication protocols and safety procedures during hazardous material incidents.\"]}'),
(24, 18, 6, '2026-05-07 11:52:38', '2026-05-07 11:52:38', 33.33, 3, 1, 'graded', '2026-05-07 11:52:38', '{\"summary\": \"The trainee demonstrated limited knowledge in fire emergency response protocols, correctly identifying the appropriate communication parties but failing in initial announcement and final reporting procedures.\", \"strengths\": [\"Correctly identified the appropriate communication parties during the fire incident.\"], \"weaknesses\": [\"Incorrect initial communication method for announcing the fire emergency.\", \"Failed to identify the proper final reporting procedure after managing the fire incident.\"], \"recommendations\": [\"Review and reinforce the protocol for announcing Code Red emergencies using the internal overhead speaker system and wireless communication devices.\", \"Emphasize the importance of preparing and submitting a joint incident report with relevant specialists to facility leadership after the incident.\"]}'),
(25, 18, 6, '2026-05-07 11:52:38', '2026-05-07 11:52:38', 33.33, 3, 1, 'graded', '2026-05-07 11:52:38', '{\"summary\": \"The trainee demonstrated partial understanding of fire emergency response protocols, correctly identifying key communication partners but failing to execute proper initial communication and final reporting steps.\", \"strengths\": [\"Correctly identified the appropriate communication partners during a fire incident.\"], \"weaknesses\": [\"Incorrect initial communication method to announce the fire emergency.\", \"Failed to recognize the proper final reporting procedure after managing the fire incident.\"], \"recommendations\": [\"Emphasize the importance of promptly announcing Code Red through the internal overhead speaker system and wireless communication devices.\", \"Train on the necessity of preparing and submitting a detailed joint incident report to facility leadership after the incident.\", \"Reinforce the sequence and protocols for communication during all phases of a fire emergency.\"]}'),
(26, 19, 6, '2026-05-07 12:02:08', '2026-05-07 12:02:08', 33.33, 3, 1, 'graded', '2026-05-07 12:02:08', '{\"summary\": \"The trainee demonstrated partial understanding of the elevator failure protocol, correctly prioritizing technician dispatch but missing key initial and final steps.\", \"strengths\": [\"Correctly prioritized dispatching technicians to inspect and release trapped passengers.\"], \"weaknesses\": [\"Did not record critical information and provide reassurance as the first step.\", \"Failed to report and inform the Safety & Security Manager after resolving the issue.\"], \"recommendations\": [\"Emphasize the importance of recording detailed information and providing support to trapped passengers immediately upon notification.\", \"Reinforce the protocol to report and document the incident and notify the Safety & Security Manager once the elevator is operational again.\"]}'),
(27, 19, 6, '2026-05-07 12:02:08', '2026-05-07 12:02:08', 33.33, 3, 1, 'graded', '2026-05-07 12:02:08', '{\"summary\": \"The trainee demonstrated partial understanding of the elevator failure protocol, correctly prioritizing technician dispatch but missing key initial and final steps.\", \"strengths\": [\"Correctly prioritized dispatching technicians to inspect the elevator and prioritize releasing trapped passengers.\"], \"weaknesses\": [\"Did not record critical information and provide support to trapped passengers as the first step.\", \"Failed to report and record findings or inform the Safety & Security Manager after resolving the issue.\"], \"recommendations\": [\"Emphasize the importance of gathering detailed information and reassuring trapped passengers immediately upon notification.\", \"Reinforce the need to formally report and document the incident and notify the Safety & Security Manager once the elevator is operational again.\"]}'),
(28, 20, 6, '2026-05-07 12:08:03', '2026-05-07 12:08:03', 50.00, 4, 2, 'graded', '2026-05-07 12:08:03', '{\"summary\": \"The trainee demonstrated partial understanding of the elevator failure protocol, correctly handling technical precautions but missing key initial and final communication steps.\", \"strengths\": [\"Correctly prioritized dispatching technicians to inspect and fix the elevator.\", \"Properly implemented safety measures by switching off the elevator and labeling it as out of service during maintenance.\"], \"weaknesses\": [\"Failed to take immediate action to record details and reassure trapped passengers.\", \"Did not report and record findings or inform the Safety & Security Manager after resolving the issue.\"], \"recommendations\": [\"Emphasize the importance of initial communication with trapped passengers to gather information and provide reassurance.\", \"Ensure proper reporting and communication with Safety & Security Manager after resolving elevator issues.\", \"Reinforce the full protocol sequence from notification to resolution and follow-up.\"]}'),
(29, 20, 6, '2026-05-07 12:08:03', '2026-05-07 12:08:03', 50.00, 4, 2, 'graded', '2026-05-07 12:08:03', '{\"summary\": \"The trainee demonstrated partial understanding of the elevator failure protocol, correctly handling technical inspection and safety labeling but missing key initial and final communication steps.\", \"strengths\": [\"Correctly prioritized dispatching technicians to inspect and fix the elevator.\", \"Properly switched off the elevator and labeled it as out of service during maintenance.\"], \"weaknesses\": [\"Failed to immediately record and inquire about trapped passengers\' status and provide reassurance.\", \"Did not report and record findings or inform Safety & Security Manager after resolution.\"], \"recommendations\": [\"Emphasize the importance of initial communication and reassurance to trapped passengers.\", \"Reinforce the need to document and report the incident and resolution to the Safety & Security Manager.\", \"Provide additional training on comprehensive crisis communication protocols.\"]}'),
(30, 21, 6, '2026-05-07 12:20:08', '2026-05-07 12:20:08', 40.00, 5, 2, 'graded', '2026-05-07 12:20:08', '{\"summary\": \"The trainee demonstrated understanding of appropriate behavior when interacting with crowds and the need to accompany individuals entering the facility, but failed to take initial security measures, properly report crowd information, and maintain communication during the incident.\", \"strengths\": [\"Understands the importance of demonstrating patience and calmness to avoid escalating tensions.\", \"Recognizes the need to assign security personnel to accompany individuals allowed entry.\"], \"weaknesses\": [\"Did not deploy sufficient security personnel or establish security perimeters at the onset.\", \"Failed to collect and report accurate information about the crowd size and classification.\", \"Did not maintain continuous coordination and communication with specialized security authorities during the incident.\"], \"recommendations\": [\"Emphasize the importance of immediate deployment of security personnel and establishment of perimeters when a large crowd gathers.\", \"Train on accurate and timely reporting of crowd information to security administration.\", \"Stress maintaining continuous communication with all relevant security authorities throughout the incident.\"]}'),
(31, 21, 6, '2026-05-07 12:20:08', '2026-05-07 12:20:08', 40.00, 5, 2, 'graded', '2026-05-07 12:20:08', '{\"summary\": \"The trainee demonstrated understanding of appropriate behavior when interacting with crowds and the need to accompany individuals entering the facility, but lacked knowledge in initial crowd management, information reporting, and communication protocols.\", \"strengths\": [\"Understands the importance of patience and calmness in crowd interactions to avoid escalation.\", \"Recognizes the need to assign security personnel to accompany individuals allowed entry.\"], \"weaknesses\": [\"Failed to identify the correct first step in managing a large crowd (deploying security personnel and establishing perimeters).\", \"Did not recognize the importance of collecting and reporting detailed information about the crowd.\", \"Incorrectly handled communication by delaying coordination with security authorities until after the incident.\"], \"recommendations\": [\"Emphasize the importance of immediate deployment of security personnel and establishing security perimeters upon noticing a large crowd.\", \"Train on systematic collection and reporting of crowd information to security administration.\", \"Stress continuous and proactive communication with specialized security authorities during incidents.\"]}');

