CREATE TABLE `trainings` (
  `id` int(11) NOT NULL,
  `created_by` int(11) NOT NULL,
  `scenario_id` varchar(100) NOT NULL,
  `scenario_title` varchar(255) NOT NULL,
  `domain` varchar(100) DEFAULT NULL,
  `facility` varchar(100) DEFAULT NULL,
  `selected_role` varchar(150) DEFAULT NULL,
  `language` varchar(20) NOT NULL DEFAULT 'en',
  `difficulty` varchar(50) DEFAULT NULL,
  `n_scenarios` int(11) NOT NULL DEFAULT 1,
  `q_per_scenario` int(11) NOT NULL DEFAULT 5,
  `ai_payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`ai_payload`)),
  `validator_report` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`validator_report`)),
  `status` enum('draft','assigned','completed') DEFAULT 'draft',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `duration_minutes` int(11) NOT NULL DEFAULT 10
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- إرجاع أو استيراد بيانات الجدول `trainings`
