INSERT INTO `trainings` (`id`, `created_by`, `scenario_id`, `scenario_title`, `domain`, `facility`, `selected_role`, `language`, `difficulty`, `n_scenarios`, `q_per_scenario`, `ai_payload`, `validator_report`, `status`, `created_at`, `duration_minutes`) VALUES
(2, 5, 'UTIL_BMB_001', 'الاستجابة لتهديد قنبلة (الرمز الأسود) - الطاقم الطبي', NULL, NULL, 'Medical Staff', 'ar', 'easy', 1, 3, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_BMB_001_MED_001\", \"title\": \"الاستجابة لتهديد قنبلة (الرمز الأسود) - الطاقم الطبي\", \"role\": \"الطاقم الطبي\", \"narrative\": \"أثناء دوامك في المستشفى، تتلقى إشعارًا بوجود تهديد بقنبلة داخل المنشأة. يجب عليك التصرف بسرعة واتباع الإجراءات المعتمدة لضمان سلامة المرضى والزملاء والتعاون مع السلطات المختصة.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"الطاقم الطبي\", \"question\": \"ما هو الإجراء الأول الذي يجب اتخاذه عند تلقي تقرير عن تهديد بقنبلة في المستشفى؟\", \"choices\": [\"إبلاغ السلطات المختصة عبر أرقام الطوارئ المعتمدة والتواصل مع قيادة المنشأة لتفعيل الرمز الأسود\", \"بدء إخلاء المرضى والموظفين فورًا دون انتظار التعليمات\", \"محاولة تفكيك القنبلة بنفسك لتقليل الخطر\", \"تجاهل التهديد إذا لم يكن هناك دليل واضح\"], \"answer_index\": 0, \"rationale\": \"يجب أولاً إبلاغ السلطات المختصة عبر أرقام الطوارئ المعتمدة والتواصل مع قيادة المنشأة لتفعيل الرمز الأسود كما هو موضح في الإجراءات المعتمدة.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R02\"]}, {\"item_id\": \"Q2\", \"role\": \"الطاقم الطبي\", \"question\": \"متى يجب تنفيذ إخلاء المرضى والموظفين من المنشأة؟\", \"choices\": [\"عند توجيه قيادة الحادث وبحسب شدة وموقع التهديد\", \"عند سماع أي إشاعة عن وجود تهديد\", \"فور تلقي أي تقرير عن تهديد بالقنبلة دون انتظار التعليمات\", \"بعد انتهاء التحقيق في مصدر التهديد فقط\"], \"answer_index\": 0, \"rationale\": \"يتم تنفيذ الإخلاء فقط عندما توجه قيادة الحادث بذلك وبحسب شدة وموقع التهديد لضمان سلامة الجميع.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R08\"]}, {\"item_id\": \"Q3\", \"role\": \"الطاقم الطبي\", \"question\": \"كيف يجب على الطاقم الطبي التعامل مع التوجيهات الصادرة من المتخصصين في هذا النوع من الحوادث؟\", \"choices\": [\"اتباع جميع التوجيهات الفنية والتعليمات بدقة لتقليل المخاطر المحتملة\", \"تجاهل التوجيهات إذا كانت معقدة أو غير واضحة\", \"تعديل التوجيهات حسب تقدير الطاقم الطبي\", \"الانتظار حتى انتهاء الحادث قبل اتخاذ أي إجراء\"], \"answer_index\": 0, \"rationale\": \"يجب اتباع جميع التوجيهات الفنية والتعليمات الصادرة من المتخصصين بدقة لتقليل المخاطر المحتملة.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R03\"]}]}]}', '{\"fails\": 3, \"issues\": [{\"type\": \"UNSUPPORTED\", \"item\": \"Q1\", \"msg\": \"Correct answer not supported by cited evidence\", \"correct_choice\": \"إبلاغ السلطات المختصة عبر أرقام الطوارئ المعتمدة والتواصل مع قيادة المنشأة لتفعيل الرمز الأسود\", \"evidence_used\": [\"UTIL_BMB_001_R02\"]}, {\"type\": \"UNSUPPORTED\", \"item\": \"Q2\", \"msg\": \"Correct answer not supported by cited evidence\", \"correct_choice\": \"عند توجيه قيادة الحادث وبحسب شدة وموقع التهديد\", \"evidence_used\": [\"UTIL_BMB_001_R08\"]}, {\"type\": \"UNSUPPORTED\", \"item\": \"Q3\", \"msg\": \"Correct answer not supported by cited evidence\", \"correct_choice\": \"اتباع جميع التوجيهات الفنية والتعليمات بدقة لتقليل المخاطر المحتملة\", \"evidence_used\": [\"UTIL_BMB_001_R03\"]}]}', 'assigned', '2026-04-25 20:10:06', 10),
(3, 5, 'UTIL_PNK_001', 'Child Abduction / Missing Infant Response (Code Pink)', NULL, NULL, 'Nursing Staff', 'en', 'easy', 1, 4, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_PNK_001_01\", \"title\": \"Child Abduction / Missing Infant Response (Code Pink)\", \"role\": \"Nursing Staff\", \"narrative\": \"You are a nurse working in a hospital when a report comes in about a missing infant within the facility. You must respond quickly and follow established protocols to help locate the child and ensure their safety.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Nursing Staff\", \"question\": \"What is the first action to take when a report of a missing or abducted child is received?\", \"choices\": [\"Identify the exact location of the incident and begin an immediate response\", \"Announce Code Pink over the overhead speaker system\", \"Search the outside surroundings of the building\", \"Request assistance from female security staff\"], \"answer_index\": 0, \"rationale\": \"The first step is to identify the exact location of the incident and begin an immediate response to ensure a focused and timely search.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Nursing Staff\", \"question\": \"What should nursing staff do while searching for the missing child inside the hospital?\", \"choices\": [\"Search carefully throughout the building and observe visitor behavior for anything suspicious\", \"Immediately expand the search to outside the building\", \"Only search the child’s last known location\", \"Wait for security personnel to conduct the search\"], \"answer_index\": 0, \"rationale\": \"Nursing staff are directed to search carefully throughout the building and observe the behavior of visitors and any suspicious movement to help locate the child.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R02\"]}, {\"item_id\": \"Q3\", \"role\": \"Nursing Staff\", \"question\": \"How is the hospital staff alerted to a missing child or infant within the facility?\", \"choices\": [\"By announcing Code Pink through the internal overhead speaker system repeatedly\", \"By sending an email alert to all staff\", \"By posting notices on bulletin boards\", \"By calling each department individually\"], \"answer_index\": 0, \"rationale\": \"Code Pink is announced through the internal overhead speaker system and repeated to alert staff throughout the facility quickly.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R05\"]}, {\"item_id\": \"Q4\", \"role\": \"Nursing Staff\", \"question\": \"If the child is found with a suspicious person, what should security personnel do?\", \"choices\": [\"Stop the person, verify their identity, and keep them under control until specialized security authorities arrive\", \"Immediately release the person and child\", \"Call the nursing staff to take the child away\", \"Ignore the person and continue searching\"], \"answer_index\": 0, \"rationale\": \"Security personnel must stop the suspicious person, verify their identity, and keep them under control until specialized security authorities arrive to ensure the child\'s safety.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R08\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-04-25 20:26:09', 10),
(4, 5, 'UTIL_CROWD_001', 'Managing Unauthorized Crowd Gathering at Facility Entrance', NULL, NULL, 'Security Team', 'en', 'hard', 1, 2, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_CROWD_001_S1\", \"title\": \"Managing Unauthorized Crowd Gathering at Facility Entrance\", \"role\": \"Security Team\", \"narrative\": \"A large group of individuals has gathered outside the hospital entrance without official permission. The crowd appears agitated and is attempting to enter the facility premises. As a member of the security team, you must manage the situation to prevent unauthorized access while maintaining calm and order.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Security Team\", \"question\": \"What is the first action you should take to manage this unauthorized crowd gathering?\", \"choices\": [\"Prevent the crowd from entering the healthcare facility and its premises unless official instructions are received.\", \"Engage the crowd with firm verbal warnings referencing previous incidents to discourage entry.\", \"Allow a few representatives to enter the facility without accompaniment to negotiate with officials.\", \"Immediately disperse the crowd using physical force to establish control.\"], \"answer_index\": 0, \"rationale\": \"The primary step is to prevent unauthorized gatherings from entering the facility unless official instructions are given, ensuring security and safety.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Security Team\", \"question\": \"How should security personnel conduct themselves during interaction with the crowd to maintain control?\", \"choices\": [\"Demonstrate patience and calmness, avoid provocative expressions, and do not create fear by referencing past incidents.\", \"Use authoritative and loud commands to intimidate the crowd into compliance.\", \"Reference previous incidents to warn the crowd of potential consequences.\", \"Show impatience to expedite crowd dispersal and prevent escalation.\"], \"answer_index\": 0, \"rationale\": \"Security personnel should remain patient and calm, avoid provocative behavior, and not create fear by referencing past incidents to maintain order and reduce tension.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R12\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-04-25 22:00:59', 10),
(5, 5, 'UTIL_ELV_001', 'تعطل المصعد مع وجود أشخاص محاصرين', NULL, NULL, 'Site Manager', 'ar', 'mixed', 1, 3, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_ELV_001_01\", \"title\": \"تعطل المصعد مع وجود أشخاص محاصرين\", \"role\": \"مدير الموقع\", \"narrative\": \"أثناء عملك كمدير الموقع، تم الإبلاغ عن توقف أحد المصاعد مع وجود أشخاص محاصرين بداخله. يجب عليك اتخاذ الإجراءات المناسبة لضمان سلامة الأشخاص المحاصرين وإدارة الوضع بشكل فعال.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"مدير الموقع\", \"question\": \"ما هي الخطوة الأولى التي يجب اتخاذها عند معرفة وجود أشخاص محاصرين في المصعد؟\", \"choices\": [\"تسجيل أسماء الأشخاص المحاصرين، الوقت، والموقع، والاستفسار عن عددهم وحالتهم الصحية\", \"إبلاغ مدير السلامة والأمن عبر التحويلة 7777\", \"إرسال الفنيين لفحص المصعد وتحديد السبب\", \"إيقاف المصعد ووضع لافتة \'خارج الخدمة\' في كل طابق\"], \"answer_index\": 0, \"rationale\": \"الخطوة الأولى هي تسجيل أسماء الأشخاص المحاصرين، الوقت، والموقع، والاستفسار عن عددهم وحالتهم الصحية، وتقديم الدعم والإرشادات لهم حتى وصول المساعدة.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R03\"]}, {\"item_id\": \"Q2\", \"role\": \"مدير الموقع\", \"question\": \"بعد التأكد من وجود أشخاص محاصرين، ما الإجراء التالي الذي يجب اتخاذه لضمان سرعة التعامل مع المشكلة؟\", \"choices\": [\"إبلاغ مدير السلامة والأمن عبر التحويلة 7777\", \"إرسال الفنيين لفحص المصعد وتحديد السبب وإعطاء أولوية لإخراج المحاصرين\", \"الاتصال بالمهندس المسؤول لإجراء فحص متابعة\", \"إيقاف المصعد ووضع لافتة \'خارج الخدمة\' في كل طابق\"], \"answer_index\": 1, \"rationale\": \"يجب إرسال الفنيين لفحص المصعد وتحديد السبب مع إعطاء أولوية لإخراج الأشخاص المحاصرين.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R04\"]}, {\"item_id\": \"Q3\", \"role\": \"مدير الموقع\", \"question\": \"بعد انتهاء المشكلة وإعادة تشغيل المصعد، ما الإجراء الذي يجب اتخاذه؟\", \"choices\": [\"إبلاغ مدير السلامة والأمن بأن النظام عاد للعمل وتسجيل النتائج\", \"إيقاف المصعد ووضع لافتة \'خارج الخدمة\' في كل طابق\", \"الاتصال بالمهندس المسؤول لإجراء فحص متابعة\", \"تقديم الدعم والإرشادات للأشخاص المحاصرين\"], \"answer_index\": 0, \"rationale\": \"بعد انتهاء المشكلة يجب إبلاغ مدير السلامة والأمن بأن النظام عاد للعمل وتسجيل النتائج.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R08\"]}]}]}', '{\"fails\": 3, \"issues\": [{\"type\": \"UNSUPPORTED\", \"item\": \"Q1\", \"msg\": \"Correct answer not supported by cited evidence\", \"correct_choice\": \"تسجيل أسماء الأشخاص المحاصرين، الوقت، والموقع، والاستفسار عن عددهم وحالتهم الصحية\", \"evidence_used\": [\"UTIL_ELV_001_R03\"]}, {\"type\": \"UNSUPPORTED\", \"item\": \"Q2\", \"msg\": \"Correct answer not supported by cited evidence\", \"correct_choice\": \"إرسال الفنيين لفحص المصعد وتحديد السبب وإعطاء أولوية لإخراج المحاصرين\", \"evidence_used\": [\"UTIL_ELV_001_R04\"]}, {\"type\": \"UNSUPPORTED\", \"item\": \"Q3\", \"msg\": \"Correct answer not supported by cited evidence\", \"correct_choice\": \"إبلاغ مدير السلامة والأمن بأن النظام عاد للعمل وتسجيل النتائج\", \"evidence_used\": [\"UTIL_ELV_001_R08\"]}]}', 'assigned', '2026-04-25 22:37:34', 10),
(7, 5, 'UTIL_SLV_001', 'Active Shooter Response Coordination', NULL, NULL, 'Security Operations Room', 'en', 'hard', 1, 2, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_SLV_001_01\", \"title\": \"Active Shooter Response Coordination\", \"role\": \"Security Operations Room\", \"narrative\": \"You are in the Security Operations Room when a report comes in about an armed person inside the healthcare facility. Your team must act quickly to verify the report, communicate the threat, and coordinate response efforts to ensure safety and containment.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Security Operations Room\", \"question\": \"What is the first action you should take upon receiving a report of an armed person inside the facility?\", \"choices\": [\"Announce Code Silver immediately over the overhead speaker system.\", \"Verify the source of the report and the exact location of the armed person.\", \"Collect detailed information about the armed person including appearance and weapon type.\", \"Secure exit routes and guide evacuation of persons in the incident zone.\"], \"answer_index\": 1, \"rationale\": \"The initial priority is to rapidly verify the source and exact location of the armed person to ensure the accuracy of the threat before further actions.\", \"evidence_chunk_ids\": [\"UTIL_SLV_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Security Operations Room\", \"question\": \"After verifying the threat, what is the appropriate next step to alert security teams and the facility?\", \"choices\": [\"Collect all available security information about the armed person.\", \"Announce Code Silver through the internal overhead speaker system and wireless devices to security teams.\", \"Secure exit routes and guide evacuation or protected movement.\", \"Coordinate with specialized security teams and relevant authorities.\"], \"answer_index\": 1, \"rationale\": \"Announcing Code Silver multiple times via overhead speakers and wireless communication devices ensures that all security teams and staff are promptly alerted to the emergency.\", \"evidence_chunk_ids\": [\"UTIL_SLV_001_R04\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-06 07:41:14', 2),
(8, 5, 'UTIL_SLV_001', 'Active Shooter Response (Code Silver) for Medical Staff', NULL, NULL, 'Medical Staff', 'en', 'hard', 1, 2, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_SLV_001_01\", \"title\": \"Active Shooter Response (Code Silver) for Medical Staff\", \"role\": \"Medical Staff\", \"narrative\": \"You are a member of the medical staff in a healthcare facility when a report comes in about an armed person inside the building. You must respond quickly and appropriately to ensure your safety, the safety of patients, and to assist in the emergency response.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Medical Staff\", \"question\": \"What is the first step the security operations room must take upon receiving a report of an armed person inside the healthcare facility?\", \"choices\": [\"Announce Code Silver immediately over the overhead speaker system.\", \"Rapidly verify the source of the report and the exact location of the armed person.\", \"Collect detailed descriptions of the armed person including weapon type and number of injured.\", \"Prevent patients, staff, and visitors from approaching the location of the armed person.\"], \"answer_index\": 1, \"rationale\": \"The security operations room must first rapidly verify the source of the report and the exact location of the armed person to ensure accurate information before further actions.\", \"evidence_chunk_ids\": [\"UTIL_SLV_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Medical Staff\", \"question\": \"As medical staff, what should you do when attempting to reach injured persons during a Code Silver incident?\", \"choices\": [\"Attempt to reach injured persons alone to provide immediate care.\", \"Wait for the armed person to be neutralized before approaching injured persons.\", \"Attempt to reach injured persons together with medical staff for safe transfer while maintaining the highest standards of protection and safety.\", \"Focus solely on securing your own safety and avoid approaching injured persons until security clears the area.\"], \"answer_index\": 2, \"rationale\": \"Medical staff should attempt to reach injured persons together with other medical staff for safe transfer, while maintaining the highest standards of protection and safety.\", \"evidence_chunk_ids\": [\"UTIL_SLV_001_R08\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-06 08:04:31', 2),
(9, 5, 'UTIL_BMB_001', 'Bomb Threat Response for Relevant Specialists', NULL, NULL, 'Relevant Specialists', 'en', 'mixed', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_BMB_001_RS01\", \"title\": \"Bomb Threat Response for Relevant Specialists\", \"role\": \"Relevant Specialists\", \"narrative\": \"You are a relevant specialist responding to a bomb threat reported at the hospital. Your role is critical in assessing the threat, guiding security personnel, coordinating with authorities, and ensuring the safety of all individuals in the facility. You must follow established protocols and communicate effectively with incident command and facility leadership.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Relevant Specialists\", \"question\": \"What is the first action the security operations room must take upon receiving a bomb threat report?\", \"choices\": [\"Immediately evacuate all patients and staff\", \"Verify the source of the report and collect initial information\", \"Notify specialized authorities through emergency numbers\", \"Warn security personnel not to approach suspicious objects\"], \"answer_index\": 1, \"rationale\": \"The security operations room must rapidly verify the source of the report and collect initial information related to the threat before taking further actions.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Relevant Specialists\", \"question\": \"Who should be notified immediately after verifying a bomb threat report?\", \"choices\": [\"Facility leadership only\", \"All hospital staff via overhead speaker\", \"Relevant specialized authorities through approved emergency numbers\", \"Security personnel on duty\"], \"answer_index\": 2, \"rationale\": \"Relevant specialized authorities must be notified immediately through approved emergency numbers, and facility leadership must be communicated with to determine Code Black activation.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R02\"]}, {\"item_id\": \"Q3\", \"role\": \"Relevant Specialists\", \"question\": \"What instruction should be given to security personnel regarding suspicious objects before specialists arrive?\", \"choices\": [\"Attempt to move or open suspicious objects carefully\", \"Isolate the area but do not move or examine suspicious objects\", \"Ignore suspicious objects until evacuation is complete\", \"Collect suspicious objects for evidence\"], \"answer_index\": 1, \"rationale\": \"Security personnel must be warned not to move, examine, open, or approach suspicious objects until specialists arrive and assess the scene.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R06\"]}, {\"item_id\": \"Q4\", \"role\": \"Relevant Specialists\", \"question\": \"When should evacuation of patients, staff, and others be executed?\", \"choices\": [\"Immediately upon receiving the bomb threat report\", \"Only after specialists have assessed the suspicious object\", \"When directed by incident command based on threat severity and location\", \"After notifying all hospital departments\"], \"answer_index\": 2, \"rationale\": \"Evacuation must be executed when directed by incident command and according to the severity and location of the threat.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R08\"]}, {\"item_id\": \"Q5\", \"role\": \"Relevant Specialists\", \"question\": \"What is essential for specialists to do during the bomb threat incident to reduce risks?\", \"choices\": [\"Follow all directions and technical guidance issued by specialists responsible for this type of incident\", \"Make independent decisions without consulting incident command\", \"Focus only on evacuating patients\", \"Delay communication until all information is confirmed\"], \"answer_index\": 0, \"rationale\": \"Strictly following all directions and technical guidance issued by specialists responsible for this type of incident is essential to reduce potential risks.\", \"evidence_chunk_ids\": [\"UTIL_BMB_001_R03\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 07:20:10', 4),
(10, 5, 'UTIL_PNK_001', 'Child Abduction / Missing Infant Response (Code Pink)', NULL, NULL, 'Female Security Staff', 'en', 'mixed', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_PNK_001_01\", \"title\": \"Child Abduction / Missing Infant Response (Code Pink)\", \"role\": \"Female Security Staff\", \"narrative\": \"You are a female security staff member at the hospital. A Code Pink has been announced due to a report of a missing infant. Your role is critical in assisting the search, especially when female companions or visitors need to be inspected as part of the search process.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Female Security Staff\", \"question\": \"What is the first action the security operations room must take upon receiving a report of a missing or abducted child?\", \"choices\": [\"Identify the exact location of the incident and begin an immediate response\", \"Announce Code Pink over the overhead speaker system\", \"Direct nursing staff to search the building\", \"Request assistance from female security staff\"], \"answer_index\": 0, \"rationale\": \"The initial step is to identify the exact location of the incident and start an immediate response to ensure a focused and timely search.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Female Security Staff\", \"question\": \"As female security staff, when are you specifically requested to assist during the search?\", \"choices\": [\"When inspection of female companions or visitors is required\", \"When the child is found with a suspicious person\", \"When the search expands outside the facility\", \"When Code Pink is announced\"], \"answer_index\": 0, \"rationale\": \"Female security staff are requested to assist specifically when inspection of female companions or visitors is needed during the search process.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R07\"]}, {\"item_id\": \"Q3\", \"role\": \"Female Security Staff\", \"question\": \"What should security personnel do if the missing child is found with a suspicious person?\", \"choices\": [\"Stop the person, verify their identity, and keep them under control until specialized security authorities arrive\", \"Immediately release the person and continue searching\", \"Call nursing staff to handle the situation\", \"Expand the search to the outside surroundings\"], \"answer_index\": 0, \"rationale\": \"Security personnel must stop the suspicious person, verify their identity, and maintain control until specialized security authorities arrive to ensure safety.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R08\"]}, {\"item_id\": \"Q4\", \"role\": \"Female Security Staff\", \"question\": \"What action is taken to alert staff throughout the facility about the missing child?\", \"choices\": [\"Announce Code Pink through the internal overhead speaker system and repeat the announcement\", \"Send text messages to all staff\", \"Post signs at all entrances\", \"Call each department individually\"], \"answer_index\": 0, \"rationale\": \"Code Pink is announced through the internal overhead speaker system and repeated to alert all staff throughout the facility promptly.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R05\"]}, {\"item_id\": \"Q5\", \"role\": \"Female Security Staff\", \"question\": \"If the child is not found inside the facility after the initial search, what is the next step?\", \"choices\": [\"Expand the search to the outside surroundings and provide security authorities with all incident details and actions taken\", \"Stop the search and wait for further instructions\", \"Focus only on nursing staff to continue searching inside\", \"Announce Code Pink again inside the facility\"], \"answer_index\": 0, \"rationale\": \"If the child is not found inside, the search must be expanded outside and security authorities must be informed of all details and actions taken to coordinate further response.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R09\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 08:11:26', 10),
(11, 5, 'UTIL_YLW_001', 'External Disaster Response Activation', NULL, NULL, 'Facility Leadership', 'en', 'mixed', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_YLW_001_01\", \"title\": \"External Disaster Response Activation\", \"role\": \"Facility Leadership\", \"narrative\": \"You are the facility leader responsible for managing the hospital\'s response to an external disaster report. Upon receiving initial information about a disaster from an external party, you must ensure proper verification, communication, and activation of emergency plans to prepare the facility for incoming casualties and potential hazards.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Facility Leadership\", \"question\": \"What is the first action the security team must take upon receiving a report about an external disaster?\", \"choices\": [\"Verify the source, type, magnitude, location, and expected casualties of the disaster\", \"Immediately announce Code Yellow over the overhead speaker system\", \"Activate the facility external disaster emergency plan\", \"Implement personal protective equipment measures\"], \"answer_index\": 0, \"rationale\": \"The security team must first verify the source of the report, the type and magnitude of the disaster, the disaster location, and the approximate number and type of expected casualties before other actions.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Facility Leadership\", \"question\": \"After verification of the disaster report, what is the next step to prepare the facility for the external disaster?\", \"choices\": [\"Announce Code Yellow through the internal overhead speaker system and wireless devices to security teams\", \"Immediately activate Code Red\", \"Send all patients home to free up space\", \"Notify the Hazmat Response Team to implement protective measures\"], \"answer_index\": 0, \"rationale\": \"Following verification, Code Yellow must be announced through the internal overhead speaker system and wireless communication devices to security teams assigned for emergency response.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R02\"]}, {\"item_id\": \"Q3\", \"role\": \"Facility Leadership\", \"question\": \"Which action should be taken to ensure the hospital is prepared internally after announcing Code Yellow?\", \"choices\": [\"Activate the facility external disaster emergency plan and implement relevant internal preparedness procedures\", \"Immediately declare Code Red\", \"Evacuate all non-essential staff\", \"Request additional ambulances from external agencies\"], \"answer_index\": 0, \"rationale\": \"The facility external disaster emergency plan must be activated and relevant internal preparedness procedures implemented to prepare the hospital for the disaster response.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R03\"]}, {\"item_id\": \"Q4\", \"role\": \"Facility Leadership\", \"question\": \"Under what circumstance might the facility escalate from Code Yellow to Code Red during an external disaster response?\", \"choices\": [\"When the number of casualties exceeds the facility response capacity or an internal disaster such as a fire occurs\", \"When the disaster is confirmed to be a biological threat\", \"When the security team requests additional support\", \"When the external disaster is declared over\"], \"answer_index\": 0, \"rationale\": \"Code Red may be announced during activation of the external disaster emergency plan when casualties exceed response capacity or an internal disaster like fire occurs.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R16\"]}, {\"item_id\": \"Q5\", \"role\": \"Facility Leadership\", \"question\": \"If the external disaster involves a biological, chemical, or radiological weapon, what must security personnel do?\", \"choices\": [\"Implement required personal protective equipment measures and comply with Hazmat Response Team instructions\", \"Immediately evacuate the facility\", \"Announce Code Red without further verification\", \"Wait for instructions from the Infection Control Department\"], \"answer_index\": 0, \"rationale\": \"Security personnel must implement required PPE measures and comply with instructions issued by the Hazmat Response Team when a pre-activated plan for biological, chemical, or radiological weapons exists.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R13\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 08:16:59', 10),
(12, 5, 'UTIL_PNK_001', 'Child Abduction / Missing Infant Response (Code Pink)', NULL, NULL, 'Nursing Staff', 'en', 'easy', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_PNK_001_01\", \"title\": \"Child Abduction / Missing Infant Response (Code Pink)\", \"role\": \"Nursing Staff\", \"narrative\": \"You are a nurse working in a hospital when a report of a missing infant is received. You must respond quickly and follow the hospital\'s Code Pink procedures to help locate the child and ensure their safety.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Nursing Staff\", \"question\": \"What is the first step after receiving a report of a missing or abducted child in the hospital?\", \"choices\": [\"Identify the exact location of the incident and begin an immediate response\", \"Announce Code Pink over the overhead speaker system\", \"Search the outside surroundings of the building\", \"Request assistance from female security staff\"], \"answer_index\": 0, \"rationale\": \"The first step is to identify the exact location of the incident and begin an immediate response to ensure a prompt and organized search.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Nursing Staff\", \"question\": \"During the search for the missing child, what should nursing staff and security personnel do?\", \"choices\": [\"Search carefully throughout the building and observe visitor behavior for suspicious movement\", \"Immediately search the outside surroundings of the building\", \"Only search the child’s last known location\", \"Wait for specialized security authorities before starting the search\"], \"answer_index\": 0, \"rationale\": \"Nursing staff and security personnel must search carefully throughout the building while observing visitors and any suspicious movement to locate the child quickly.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R02\"]}, {\"item_id\": \"Q3\", \"role\": \"Nursing Staff\", \"question\": \"How should the hospital alert staff throughout the facility about the missing child?\", \"choices\": [\"Announce Code Pink through the internal overhead speaker system and repeat the announcement\", \"Send an email to all staff\", \"Call each department individually\", \"Post signs at the hospital entrances\"], \"answer_index\": 0, \"rationale\": \"Announcing Code Pink through the internal overhead speaker system and repeating it ensures all staff are promptly alerted throughout the facility.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R05\"]}, {\"item_id\": \"Q4\", \"role\": \"Nursing Staff\", \"question\": \"If the child is found with a suspicious person, what action should security personnel take?\", \"choices\": [\"Stop the person, verify their identity, and keep them under control until specialized security authorities arrive\", \"Immediately release the person and child\", \"Call the nursing staff to handle the situation\", \"Ignore the situation and continue searching\"], \"answer_index\": 0, \"rationale\": \"Security personnel must stop the suspicious person, verify their identity, and keep them under control until specialized security authorities arrive to ensure safety.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R08\"]}, {\"item_id\": \"Q5\", \"role\": \"Nursing Staff\", \"question\": \"What should be done if the child is not found inside the facility after the initial search?\", \"choices\": [\"Expand the search to the outside surroundings and provide security authorities with all incident details and actions taken\", \"Stop the search and wait for further instructions\", \"Only search the parking lot\", \"Announce Code Pink again and restart the internal search\"], \"answer_index\": 0, \"rationale\": \"If the child is not found inside, the search must be expanded outside and security authorities must be informed with all relevant details to continue the search effectively.\", \"evidence_chunk_ids\": [\"UTIL_PNK_001_R09\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 08:36:19', 10),
(13, 5, 'UTIL_HAZ_001', 'Hazardous Material Spill Response (Code Orange)', NULL, NULL, 'Facility Leadership', 'en', 'hard', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_HAZ_001_FAC_LEAD\", \"title\": \"Hazardous Material Spill Response (Code Orange)\", \"role\": \"Facility Leadership\", \"narrative\": \"A chemical spill has been reported within the hospital premises. As Facility Leadership, you must coordinate the response efforts, ensure communication with relevant teams, and oversee the safety protocols to manage the incident effectively.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Facility Leadership\", \"question\": \"What is the first step the security operations room should take upon receiving a report of a chemical spill?\", \"choices\": [\"Announce Code Orange through the internal overhead speaker system.\", \"Communicate directly with Civil Defense and the Hazmat Response Team.\", \"Rapidly verify the source of the report and the exact incident location.\", \"Prepare and submit a joint incident report with specialists.\"], \"answer_index\": 2, \"rationale\": \"The initial action is to verify the source and exact location of the chemical spill report to ensure accurate response.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Facility Leadership\", \"question\": \"How should the announcement of Code Orange be made within the facility?\", \"choices\": [\"Send a signal through wireless communication devices only.\", \"Announce Code Orange once through the internal overhead speaker system.\", \"Announce Code Orange through the internal overhead speaker system multiple times and send a wireless signal to security teams.\", \"Communicate directly with Civil Defense and the Hazmat Response Team.\"], \"answer_index\": 2, \"rationale\": \"Code Orange must be announced several times over the overhead system and simultaneously signaled via wireless devices to security teams.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R02\"]}, {\"item_id\": \"Q3\", \"role\": \"Facility Leadership\", \"question\": \"What must be ensured before allowing specialists access to the chemical spill incident site?\", \"choices\": [\"They have been briefed on the incident location.\", \"They are wearing the designated clothing and protective equipment for chemical spill response.\", \"They have communicated with Civil Defense.\", \"They have submitted a joint incident report.\"], \"answer_index\": 1, \"rationale\": \"Specialists must wear the designated protective clothing and equipment before accessing the incident site to ensure safety.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R07\"]}, {\"item_id\": \"Q4\", \"role\": \"Facility Leadership\", \"question\": \"Who should Facility Leadership communicate with directly regarding the chemical spill incident?\", \"choices\": [\"Only the internal security teams.\", \"Civil Defense and the Hazmat Response Team in the facility.\", \"The hospital patients and visitors.\", \"External media outlets.\"], \"answer_index\": 1, \"rationale\": \"Facility Leadership must communicate directly with Civil Defense and the Hazmat Response Team to coordinate the response.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R03\"]}, {\"item_id\": \"Q5\", \"role\": \"Facility Leadership\", \"question\": \"What is the final reporting step after managing the hazardous material spill incident?\", \"choices\": [\"Prepare and submit a joint incident report with relevant specialists and Civil Defense to facility leadership.\", \"Announce the end of Code Orange over the overhead system.\", \"Comply with all directions issued by incident command.\", \"Conduct a safety drill for future incidents.\"], \"answer_index\": 0, \"rationale\": \"The final step is to prepare and submit a joint incident report with specialists and Civil Defense to facility leadership for documentation and review.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R10\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 08:42:46', 10),
(14, 5, 'UTIL_ELV_001', 'Responding to Elevator Failure with Trapped Individuals', NULL, NULL, 'Safety & Security Officer', 'en', 'mixed', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_ELV_001_S01\", \"title\": \"Responding to Elevator Failure with Trapped Individuals\", \"role\": \"Safety & Security Officer\", \"narrative\": \"During your shift, an elevator failure is reported with people trapped inside. Your responsibility is to ensure their safety, coordinate the response, and communicate effectively with relevant personnel.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Safety & Security Officer\", \"question\": \"What is the first step you should take upon learning that people are trapped in the elevator?\", \"choices\": [\"Record the names, time, location, number of trapped people, and their health status; provide support and reassurance.\", \"Immediately call the engineer in charge for a follow-up inspection.\", \"Switch off the elevator and label it as \'out of service\' on each floor.\", \"Report and record findings after the issue is resolved.\"], \"answer_index\": 0, \"rationale\": \"The first priority is to gather detailed information about the trapped individuals and provide them with support and reassurance until help arrives.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R03\"]}, {\"item_id\": \"Q2\", \"role\": \"Safety & Security Officer\", \"question\": \"Who should you inform immediately after confirming trapped individuals in the elevator?\", \"choices\": [\"The Safety & Security Manager via extension 7777.\", \"The maintenance technician on site.\", \"The hospital administration office.\", \"The elevator manufacturer.\"], \"answer_index\": 0, \"rationale\": \"The Safety & Security Manager must be informed promptly through the designated extension to coordinate the response.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R02\"]}, {\"item_id\": \"Q3\", \"role\": \"Safety & Security Officer\", \"question\": \"What action should be taken regarding the elevator if maintenance is ongoing during the failure?\", \"choices\": [\"Switch off the elevator and label it as \'out of service\' and under maintenance on each floor.\", \"Keep the elevator running to avoid trapping more people.\", \"Notify trapped individuals to remain calm without switching off the elevator.\", \"Call the engineer to conduct a follow-up inspection immediately.\"], \"answer_index\": 0, \"rationale\": \"To prevent use of the elevator during maintenance, it must be switched off and clearly labeled on each floor.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R07\"]}, {\"item_id\": \"Q4\", \"role\": \"Safety & Security Officer\", \"question\": \"What is the appropriate next step after informing the Safety & Security Manager about the elevator failure with trapped people?\", \"choices\": [\"Dispatch technicians to inspect the elevator, determine the cause, and prioritize releasing trapped people.\", \"Call the engineer to conduct a follow-up inspection immediately.\", \"Switch off the elevator and label it as \'out of service\'.\", \"Report and record findings after the issue is resolved.\"], \"answer_index\": 0, \"rationale\": \"Technicians should be dispatched promptly to inspect and prioritize the release of trapped individuals.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R04\"]}, {\"item_id\": \"Q5\", \"role\": \"Safety & Security Officer\", \"question\": \"What should be done after the elevator issue has been resolved and the system is back in operation?\", \"choices\": [\"Report and record findings and inform the Safety & Security Manager that the system returned to operation.\", \"Immediately switch off the elevator and label it as \'out of service\'.\", \"Call the engineer to start a new inspection.\", \"Provide support and reassurance to trapped individuals again.\"], \"answer_index\": 0, \"rationale\": \"After resolution, it is important to document the incident and inform the Safety & Security Manager that normal operation has resumed.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R08\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 08:53:39', 10),
(15, 5, 'UTIL_CROWD_001', 'Crowd Gathering Control and Management', NULL, NULL, 'Facility Management', 'en', 'mixed', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_CROWD_001_FM_01\", \"title\": \"Crowd Gathering Control and Management\", \"role\": \"Facility Management\", \"narrative\": \"You are responsible for managing crowd gatherings around the healthcare facility. Your goal is to prevent unauthorized access, ensure security personnel are properly deployed, and maintain calm and order until the situation is fully resolved.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Facility Management\", \"question\": \"What is the first step to take when a crowd begins to gather near the healthcare facility without official permission?\", \"choices\": [\"Allow the crowd to enter if they seem peaceful.\", \"Prevent the crowd from entering the healthcare facility and its premises.\", \"Call the media to report the gathering.\", \"Ignore the crowd unless they become violent.\"], \"answer_index\": 1, \"rationale\": \"Unauthorized crowds should be prevented from entering the healthcare facility unless official instructions are received to allow entry.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Facility Management\", \"question\": \"How should security personnel behave when interacting with a crowd to maintain order?\", \"choices\": [\"Use firm and loud commands to intimidate the crowd.\", \"Demonstrate patience and calmness, avoid provocative behavior, and do not create fear by referencing past incidents.\", \"Ignore the crowd and focus on other tasks.\", \"Physically push the crowd back to disperse them quickly.\"], \"answer_index\": 1, \"rationale\": \"Security personnel should demonstrate patience and calmness, avoid provocative verbal or physical expressions, and avoid creating fear by referencing previous incidents.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R12\"]}, {\"item_id\": \"Q3\", \"role\": \"Facility Management\", \"question\": \"What should be done regarding security personnel deployment during a crowd gathering?\", \"choices\": [\"Deploy a minimal number of security personnel to avoid escalating the situation.\", \"Deploy sufficient security personnel to manage the gathering and establish security perimeters when required.\", \"Only deploy security personnel if the crowd becomes violent.\", \"Allow volunteers to manage the crowd instead of security personnel.\"], \"answer_index\": 1, \"rationale\": \"Sufficient security personnel should be deployed to manage the gathering and establish security perimeters when required.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R03\"]}, {\"item_id\": \"Q4\", \"role\": \"Facility Management\", \"question\": \"If certain individuals are allowed entry to meet responsible officials inside the facility, what security measure should be taken?\", \"choices\": [\"Allow them to enter without any security accompaniment.\", \"Assign an adequate number of security personnel to accompany these persons inside the facility.\", \"Let the crowd escort them inside.\", \"Request the individuals to wait outside until the crowd disperses.\"], \"answer_index\": 1, \"rationale\": \"An adequate number of security personnel should accompany persons allowed entry to meet responsible officials inside the facility.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R08\"]}, {\"item_id\": \"Q5\", \"role\": \"Facility Management\", \"question\": \"What is the appropriate action to take after the crowd gathering situation has been managed?\", \"choices\": [\"Stop monitoring once the crowd starts to disperse.\", \"Continue monitoring until the situation ends completely and ensure the crowd disperses from the surrounding area.\", \"Immediately remove all security personnel to save resources.\", \"Allow the crowd to remain near the facility as long as they are quiet.\"], \"answer_index\": 1, \"rationale\": \"The situation should be monitored until it ends completely and the crowd disperses from the surrounding area of the healthcare facility.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R10\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 11:19:52', 10);
INSERT INTO `trainings` (`id`, `created_by`, `scenario_id`, `scenario_title`, `domain`, `facility`, `selected_role`, `language`, `difficulty`, `n_scenarios`, `q_per_scenario`, `ai_payload`, `validator_report`, `status`, `created_at`, `duration_minutes`) VALUES
(16, 5, 'UTIL_YLW_001', 'External Disaster Response Activation and Coordination', NULL, NULL, 'Planning and Preparedness Unit', 'en', 'mixed', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_YLW_001_01\", \"title\": \"External Disaster Response Activation and Coordination\", \"role\": \"Planning and Preparedness Unit\", \"narrative\": \"An external disaster has occurred, requiring the hospital to activate its emergency response protocols. As a member of the Planning and Preparedness Unit, you must ensure proper activation of the external disaster emergency plan, coordinate with relevant departments, and manage communication to security teams and emergency responders to optimize readiness and safety.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Planning and Preparedness Unit\", \"question\": \"What is the first step in notifying hospital personnel and security teams about the activation of a Code Yellow external disaster response?\", \"choices\": [\"Announce Code Yellow through the internal overhead speaker system and send a signal through wireless communication devices to security teams.\", \"Directly contact ambulance command by phone to inform them of the disaster.\", \"Send an email notification to all hospital staff.\", \"Wait for the emergency departments to initiate communication.\"], \"answer_index\": 0, \"rationale\": \"The correct initial notification method is to announce Code Yellow via the internal overhead speaker system and send a wireless signal to security teams, ensuring rapid and broad communication.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R02\"]}, {\"item_id\": \"Q2\", \"role\": \"Planning and Preparedness Unit\", \"question\": \"After announcing Code Yellow, what is the next critical action to take in managing the hospital\'s response?\", \"choices\": [\"Activate the facility external disaster emergency plan and implement relevant internal preparedness procedures.\", \"Immediately declare Code Red to escalate the response.\", \"Begin evacuating all patients from the hospital.\", \"Request additional ambulances from external agencies.\"], \"answer_index\": 0, \"rationale\": \"Following the announcement, the facility external disaster emergency plan must be activated and internal preparedness procedures implemented to manage the response effectively.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R03\"]}, {\"item_id\": \"Q3\", \"role\": \"Planning and Preparedness Unit\", \"question\": \"Which departments or units should the Planning and Preparedness Unit coordinate with to raise readiness and preparedness for security personnel in the receiving area during an external disaster?\", \"choices\": [\"Ambulance command, emergency departments, and the planning and emergency preparedness unit.\", \"Infection Control Department and Hazmat Response Team only.\", \"Hospital administration and finance departments.\", \"Patient transport services and cafeteria staff.\"], \"answer_index\": 0, \"rationale\": \"Coordination with ambulance command, emergency departments, and the planning and emergency preparedness unit is essential to raise readiness and preparedness for security personnel in the receiving area.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R04\"]}, {\"item_id\": \"Q4\", \"role\": \"Planning and Preparedness Unit\", \"question\": \"Under what circumstances might the hospital escalate from Code Yellow to Code Red during an external disaster response?\", \"choices\": [\"When the number of casualties exceeds the facility response capacity or when an internal disaster such as a fire occurs.\", \"When the external disaster is declared over by local authorities.\", \"When security personnel complete their shift changes.\", \"When the Infection Control Department issues new guidelines.\"], \"answer_index\": 0, \"rationale\": \"Code Red may be announced when casualties exceed facility capacity or when an internal disaster like a fire occurs, requiring escalation of the emergency response.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R16\"]}, {\"item_id\": \"Q5\", \"role\": \"Planning and Preparedness Unit\", \"question\": \"If the external disaster involves a biological, chemical, or radiological threat, what must security personnel do according to the pre-activated response plans?\", \"choices\": [\"Implement required personal protective equipment measures and comply with instructions issued by the Hazmat Response Team.\", \"Follow standard security protocols without additional protective measures.\", \"Coordinate only with ambulance command for patient transport.\", \"Wait for instructions from hospital administration before acting.\"], \"answer_index\": 0, \"rationale\": \"Security personnel must implement required PPE measures and follow instructions from the Hazmat Response Team when a biological, chemical, or radiological threat is involved.\", \"evidence_chunk_ids\": [\"UTIL_YLW_001_R13\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 11:32:18', 10),
(17, 5, 'UTIL_HAZ_001', 'Hazardous Material Spill Response (Code Orange)', NULL, NULL, 'Security Team', 'en', 'mixed', 1, 3, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_HAZ_001_S01\", \"title\": \"Hazardous Material Spill Response (Code Orange)\", \"role\": \"Security Team\", \"narrative\": \"You are a member of the hospital security team responding to a reported chemical spill within the facility. Your responsibilities include verifying the incident, securing the area, communicating with emergency teams, and facilitating specialist access while ensuring safety protocols are followed.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Security Team\", \"question\": \"What is the first action the security operations room must take upon receiving a report of a chemical spill?\", \"choices\": [\"Immediately announce Code Orange over the overhead speaker system.\", \"Rapidly verify the source of the report and the exact incident location.\", \"Send security staff directly to the incident site without delay.\", \"Contact the hospital administration for further instructions.\"], \"answer_index\": 1, \"rationale\": \"The security operations room must first verify the source of the report and the exact incident location to ensure accurate response.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R01\"]}, {\"item_id\": \"Q2\", \"role\": \"Security Team\", \"question\": \"How should security personnel announce the Code Orange alert within the hospital?\", \"choices\": [\"Send a single wireless message to the emergency response teams.\", \"Announce Code Orange once over the overhead speaker system.\", \"Announce Code Orange several times over the overhead speaker system and send a wireless signal to security teams.\", \"Notify only the Hazmat Response Team via phone call.\"], \"answer_index\": 2, \"rationale\": \"Code Orange must be announced repeatedly over the overhead speaker system and a wireless signal sent to security teams assigned for emergency response.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R02\"]}, {\"item_id\": \"Q3\", \"role\": \"Security Team\", \"question\": \"What safety measures should security staff take when securing the hazardous spill site?\", \"choices\": [\"Remain in the affected area as long as possible to monitor the situation.\", \"Avoid direct exposure to toxic emissions, use personal protective equipment, and rotate with other staff.\", \"Wait for the Hazmat Response Team to arrive before taking any action.\", \"Only wear standard security uniforms without additional protective gear.\"], \"answer_index\": 1, \"rationale\": \"Security staff must avoid direct exposure to toxic emissions, use personal protective equipment, and rotate with other staff to avoid prolonged exposure.\", \"evidence_chunk_ids\": [\"UTIL_HAZ_001_R04\", \"UTIL_HAZ_001_R05\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 11:44:32', 10),
(18, 5, 'UTIL_FIRE_001', 'Fire Emergency Response (Code Red)', NULL, NULL, 'Civil Defense', 'en', 'mixed', 1, 3, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_FIRE_001_01\", \"title\": \"Fire Emergency Response (Code Red)\", \"role\": \"Civil Defense\", \"narrative\": \"A fire has been detected in the hospital. As a member of Civil Defense, you must coordinate with internal teams and external emergency responders to manage the situation effectively and ensure safety.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Civil Defense\", \"question\": \"What is the correct initial communication step to announce a fire emergency within the hospital?\", \"choices\": [\"Announce Code Red through the internal overhead speaker system and repeat the announcement several times, while also sending a signal through wireless communication devices to the security teams assigned for emergency response.\", \"Send an email to all hospital staff detailing the fire incident.\", \"Wait for the fire to be confirmed by the facility leadership before making any announcements.\", \"Call the National Center for Emergency and Health Crisis Management first before any internal announcements.\"], \"answer_index\": 0, \"rationale\": \"The correct procedure is to announce Code Red immediately through the internal overhead speaker system and wireless devices to alert security teams, ensuring rapid response.\", \"evidence_chunk_ids\": [\"UTIL_FIRE_001_R02\"]}, {\"item_id\": \"Q2\", \"role\": \"Civil Defense\", \"question\": \"Who should Civil Defense communicate with directly regarding the fire incident?\", \"choices\": [\"The facility firefighting unit and Civil Defense themselves.\", \"Only the hospital administration.\", \"External media outlets to inform the public.\", \"The National Center for Emergency and Health Crisis Management exclusively.\"], \"answer_index\": 0, \"rationale\": \"Civil Defense must communicate directly with the facility firefighting unit and their own team to coordinate the emergency response effectively.\", \"evidence_chunk_ids\": [\"UTIL_FIRE_001_R03\"]}, {\"item_id\": \"Q3\", \"role\": \"Civil Defense\", \"question\": \"What is the final reporting step after managing the fire incident?\", \"choices\": [\"Prepare and submit a joint incident report with the relevant specialists in the facility and Civil Defense to the facility leadership.\", \"Only notify the National Center for Emergency and Health Crisis Management without internal reporting.\", \"Send a brief verbal update to the security staff without documentation.\", \"Wait for the fire to be fully extinguished before reporting.\"], \"answer_index\": 0, \"rationale\": \"After the incident, a joint incident report must be prepared and submitted with relevant specialists and Civil Defense to the facility leadership to document the event and response.\", \"evidence_chunk_ids\": [\"UTIL_FIRE_001_R09\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 11:52:18', 5),
(19, 5, 'UTIL_ELV_001', 'Elevator Failure with Trapped Passengers', NULL, NULL, 'Engineer on duty', 'en', 'mixed', 1, 3, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_ELV_001_ENG_01\", \"title\": \"Elevator Failure with Trapped Passengers\", \"role\": \"Engineer on duty\", \"narrative\": \"During your shift as the engineer on duty, you are informed that an elevator has stopped between floors with passengers trapped inside. You need to manage the situation effectively, ensuring the safety and reassurance of the trapped individuals while coordinating the technical response and communication with hospital management.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Engineer on duty\", \"question\": \"What is your first step upon learning that people are trapped in the elevator?\", \"choices\": [\"Record the names, time, location, number of trapped people, and their health status; provide support and reassurance until help arrives.\", \"Immediately switch off the elevator and label it as \'out of service\' on each floor.\", \"Call the Safety & Security Manager through extension 7777.\", \"Dispatch technicians to inspect and determine the cause of the failure.\"], \"answer_index\": 0, \"rationale\": \"The first priority is to gather detailed information about the trapped people and provide them support and reassurance to ensure their safety and calmness until rescue.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R03\"]}, {\"item_id\": \"Q2\", \"role\": \"Engineer on duty\", \"question\": \"After confirming the trapped passengers\' status, what action should you take next?\", \"choices\": [\"Switch off the elevator and label it as \'out of service\' on each floor to prevent use during maintenance.\", \"Call the engineer in charge to conduct a follow-up inspection.\", \"Dispatch technicians to inspect the elevator, determine the cause, and prioritize releasing trapped people.\", \"Report and record findings and inform the Safety & Security Manager that the system returned to operation.\"], \"answer_index\": 2, \"rationale\": \"Technicians should be dispatched promptly to inspect the elevator, identify the cause, and prioritize releasing the trapped passengers.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R04\"]}, {\"item_id\": \"Q3\", \"role\": \"Engineer on duty\", \"question\": \"Once the elevator issue is resolved and the system is operational again, what is the appropriate final step?\", \"choices\": [\"Switch off the elevator and label it as \'out of service\' until maintenance is completed.\", \"Inform the Safety & Security Manager through extension 7777 about the issue.\", \"Report and record findings and inform the Safety & Security Manager that the system returned to operation.\", \"Call the engineer in charge to conduct a follow-up inspection.\"], \"answer_index\": 2, \"rationale\": \"After resolution, it is required to report and record the findings and inform the Safety & Security Manager that the elevator system has returned to operation.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R08\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 12:01:29', 10),
(20, 5, 'UTIL_ELV_001', 'Elevator Failure with Trapped Passengers', NULL, NULL, 'Engineer in Charge', 'en', 'mixed', 1, 4, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_ELV_001_ENG_01\", \"title\": \"Elevator Failure with Trapped Passengers\", \"role\": \"Engineer in Charge\", \"narrative\": \"An elevator in the hospital has stopped functioning unexpectedly, and there are reports of people trapped inside. As the Engineer in Charge, you are called to manage the situation, ensure the safety of the trapped individuals, and restore elevator operation as soon as possible.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Engineer in Charge\", \"question\": \"What is your immediate action upon being notified of trapped people in the elevator?\", \"choices\": [\"Record names, time, location, inquire about number and health status of trapped people, and provide reassurance until help arrives.\", \"Immediately switch off the elevator and label it out of service on each floor.\", \"Call the Safety & Security Manager through extension 7777.\", \"Dispatch technicians to inspect and fix the elevator.\"], \"answer_index\": 0, \"rationale\": \"The first priority is to gather information about the trapped people and provide support and reassurance until help arrives.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R03\"]}, {\"item_id\": \"Q2\", \"role\": \"Engineer in Charge\", \"question\": \"After being informed of the elevator failure, what is the next step you should take to address the technical issue?\", \"choices\": [\"Call the engineer in charge to conduct follow-up inspection and detect the cause of the issue.\", \"Dispatch technicians to inspect, determine the cause, and prioritize releasing trapped people.\", \"Switch off the elevator and label it as out of service on each floor.\", \"Inform the Safety & Security Manager through extension 7777.\"], \"answer_index\": 1, \"rationale\": \"Technicians should be dispatched to inspect the elevator, determine the cause, and prioritize releasing trapped people.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R04\"]}, {\"item_id\": \"Q3\", \"role\": \"Engineer in Charge\", \"question\": \"If elevator maintenance is ongoing during the failure, what precaution must be taken to prevent further use of the elevator?\", \"choices\": [\"Switch off the elevator and label it as \'out of service\' and under maintenance on each floor.\", \"Immediately call the Safety & Security Manager.\", \"Record the names and health status of trapped people.\", \"Dispatch technicians to inspect the elevator.\"], \"answer_index\": 0, \"rationale\": \"To prevent use during maintenance, the elevator must be switched off and labeled as out of service on each floor.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R07\"]}, {\"item_id\": \"Q4\", \"role\": \"Engineer in Charge\", \"question\": \"Once the elevator issue is resolved and the system is operational again, what is your responsibility?\", \"choices\": [\"Report and record findings and inform the Safety & Security Manager that the system returned to operation.\", \"Immediately dispatch technicians to inspect the elevator again.\", \"Switch off the elevator and label it as out of service.\", \"Call the trapped people to confirm their health status.\"], \"answer_index\": 0, \"rationale\": \"After resolution, the engineer must report and record findings and inform the Safety & Security Manager that the system is operational.\", \"evidence_chunk_ids\": [\"UTIL_ELV_001_R08\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 12:07:33', 10),
(21, 5, 'UTIL_CROWD_001', 'Managing a Large Crowd Gathering at Hospital Entrance', NULL, NULL, 'Security Operations Room', 'en', 'mixed', 1, 5, '{\"generated_scenarios\": [{\"scenario_id\": \"UTIL_CROWD_001_01\", \"title\": \"Managing a Large Crowd Gathering at Hospital Entrance\", \"role\": \"Security Operations Room\", \"narrative\": \"A large crowd has gathered outside the hospital entrance, causing potential disruption to hospital operations. As the Security Operations Room officer, you must coordinate the response to ensure safety, maintain order, and facilitate communication with relevant authorities.\", \"questions\": [{\"item_id\": \"Q1\", \"role\": \"Security Operations Room\", \"question\": \"What is the first step you should take upon noticing the large crowd gathering?\", \"choices\": [\"Deploy sufficient security personnel to manage the gathering and establish security perimeters.\", \"Immediately disperse the crowd using loud verbal commands.\", \"Allow the crowd to enter the facility without restrictions.\", \"Contact hospital medical staff to assist with crowd control.\"], \"answer_index\": 0, \"rationale\": \"The first step is to ensure deployment of sufficient security personnel to manage the gathering and establish security perimeters when required.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R03\"]}, {\"item_id\": \"Q2\", \"role\": \"Security Operations Room\", \"question\": \"How should security personnel behave when interacting with the crowd to avoid escalating tensions?\", \"choices\": [\"Demonstrate patience and calmness, show good conduct, avoid provocative expressions, and avoid creating fear by referencing previous incidents.\", \"Use firm and loud verbal warnings to assert authority.\", \"Ignore the crowd and focus on other tasks.\", \"Reference previous incidents to warn the crowd about consequences.\"], \"answer_index\": 0, \"rationale\": \"Security personnel should demonstrate patience and calmness, show good conduct, avoid provocative verbal or physical expressions, and avoid creating fear by referencing previous incidents.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R12\"]}, {\"item_id\": \"Q3\", \"role\": \"Security Operations Room\", \"question\": \"What information should be collected and reported to the security administration regarding the crowd?\", \"choices\": [\"Count the number of individuals involved and classify them according to the security situation.\", \"Only report if the crowd becomes violent.\", \"Report the names of individuals in the crowd.\", \"Ignore the crowd size and focus on internal hospital security.\"], \"answer_index\": 0, \"rationale\": \"It is important to count the number of individuals involved, classify them according to the security situation, and submit the information to the security administration.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R07\"]}, {\"item_id\": \"Q4\", \"role\": \"Security Operations Room\", \"question\": \"How should communication be handled during the incident?\", \"choices\": [\"Maintain continuous coordination and communication with specialized security authorities throughout the incident.\", \"Only communicate with hospital leadership after the incident is resolved.\", \"Use informal channels to quickly share information.\", \"Limit communication to internal security staff only.\"], \"answer_index\": 0, \"rationale\": \"Continuous coordination and communication with specialized security authorities during the entire incident is essential.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R06\"]}, {\"item_id\": \"Q5\", \"role\": \"Security Operations Room\", \"question\": \"If certain individuals are allowed entry to meet responsible officials inside the facility, what should be done?\", \"choices\": [\"Assign an adequate number of security personnel to accompany those individuals.\", \"Allow them to enter unaccompanied to avoid delays.\", \"Request the crowd to escort them inside.\", \"Deny entry to all individuals until the crowd disperses.\"], \"answer_index\": 0, \"rationale\": \"An adequate number of security personnel should be assigned to accompany persons allowed entry for the purpose of meeting responsible officials inside the facility.\", \"evidence_chunk_ids\": [\"UTIL_CROWD_001_R08\"]}]}]}', '{\"fails\": 0, \"issues\": []}', 'assigned', '2026-05-07 12:19:33', 10);

