INSERT INTO `training_questions` (`id`, `training_id`, `question_text`, `option_1`, `option_2`, `option_3`, `option_4`, `correct_answer_index`, `evidence_chunk_ids`, `question_order`, `created_at`) VALUES
(3, 2, 'ما هو الإجراء الأول الذي يجب اتخاذه عند تلقي تقرير عن تهديد بقنبلة في المستشفى؟', '', '', '', '', 0, '[\"UTIL_BMB_001_R02\"]', 1, '2026-04-25 20:10:06'),
(4, 2, 'متى يجب تنفيذ إخلاء المرضى والموظفين من المنشأة؟', '', '', '', '', 0, '[\"UTIL_BMB_001_R08\"]', 2, '2026-04-25 20:10:06'),
(5, 2, 'كيف يجب على الطاقم الطبي التعامل مع التوجيهات الصادرة من المتخصصين في هذا النوع من الحوادث؟', '', '', '', '', 0, '[\"UTIL_BMB_001_R03\"]', 3, '2026-04-25 20:10:06'),
(6, 3, 'What is the first action to take when a report of a missing or abducted child is received?', '', '', '', '', 0, '[\"UTIL_PNK_001_R01\"]', 1, '2026-04-25 20:26:09'),
(7, 3, 'What should nursing staff do while searching for the missing child inside the hospital?', '', '', '', '', 0, '[\"UTIL_PNK_001_R02\"]', 2, '2026-04-25 20:26:09'),
(8, 3, 'How is the hospital staff alerted to a missing child or infant within the facility?', '', '', '', '', 0, '[\"UTIL_PNK_001_R05\"]', 3, '2026-04-25 20:26:09'),
(9, 3, 'If the child is found with a suspicious person, what should security personnel do?', '', '', '', '', 0, '[\"UTIL_PNK_001_R08\"]', 4, '2026-04-25 20:26:09'),
(10, 4, 'What is the first action you should take to manage this unauthorized crowd gathering?', 'Prevent the crowd from entering the healthcare facility and its premises unless official instructions are received.', 'Engage the crowd with firm verbal warnings referencing previous incidents to discourage entry.', 'Allow a few representatives to enter the facility without accompaniment to negotiate with officials.', 'Immediately disperse the crowd using physical force to establish control.', 0, '[\"UTIL_CROWD_001_R01\"]', 1, '2026-04-25 22:01:00'),
(11, 4, 'How should security personnel conduct themselves during interaction with the crowd to maintain control?', 'Demonstrate patience and calmness, avoid provocative expressions, and do not create fear by referencing past incidents.', 'Use authoritative and loud commands to intimidate the crowd into compliance.', 'Reference previous incidents to warn the crowd of potential consequences.', 'Show impatience to expedite crowd dispersal and prevent escalation.', 0, '[\"UTIL_CROWD_001_R12\"]', 2, '2026-04-25 22:01:00'),
(12, 5, 'ما هي الخطوة الأولى التي يجب اتخاذها عند معرفة وجود أشخاص محاصرين في المصعد؟', 'تسجيل أسماء الأشخاص المحاصرين، الوقت، والموقع، والاستفسار عن عددهم وحالتهم الصحية', 'إبلاغ مدير السلامة والأمن عبر التحويلة 7777', 'إرسال الفنيين لفحص المصعد وتحديد السبب', 'إيقاف المصعد ووضع لافتة \'خارج الخدمة\' في كل طابق', 0, '[\"UTIL_ELV_001_R03\"]', 1, '2026-04-25 22:37:34'),
(13, 5, 'بعد التأكد من وجود أشخاص محاصرين، ما الإجراء التالي الذي يجب اتخاذه لضمان سرعة التعامل مع المشكلة؟', 'إبلاغ مدير السلامة والأمن عبر التحويلة 7777', 'إرسال الفنيين لفحص المصعد وتحديد السبب وإعطاء أولوية لإخراج المحاصرين', 'الاتصال بالمهندس المسؤول لإجراء فحص متابعة', 'إيقاف المصعد ووضع لافتة \'خارج الخدمة\' في كل طابق', 1, '[\"UTIL_ELV_001_R04\"]', 2, '2026-04-25 22:37:34'),
(14, 5, 'بعد انتهاء المشكلة وإعادة تشغيل المصعد، ما الإجراء الذي يجب اتخاذه؟', 'إبلاغ مدير السلامة والأمن بأن النظام عاد للعمل وتسجيل النتائج', 'إيقاف المصعد ووضع لافتة \'خارج الخدمة\' في كل طابق', 'الاتصال بالمهندس المسؤول لإجراء فحص متابعة', 'تقديم الدعم والإرشادات للأشخاص المحاصرين', 0, '[\"UTIL_ELV_001_R08\"]', 3, '2026-04-25 22:37:34'),
(18, 7, 'What is the first action you should take upon receiving a report of an armed person inside the facility?', 'Announce Code Silver immediately over the overhead speaker system.', 'Verify the source of the report and the exact location of the armed person.', 'Collect detailed information about the armed person including appearance and weapon type.', 'Secure exit routes and guide evacuation of persons in the incident zone.', 1, '[\"UTIL_SLV_001_R01\"]', 1, '2026-05-06 07:41:14'),
(19, 7, 'After verifying the threat, what is the appropriate next step to alert security teams and the facility?', 'Collect all available security information about the armed person.', 'Announce Code Silver through the internal overhead speaker system and wireless devices to security teams.', 'Secure exit routes and guide evacuation or protected movement.', 'Coordinate with specialized security teams and relevant authorities.', 1, '[\"UTIL_SLV_001_R04\"]', 2, '2026-05-06 07:41:14'),
(20, 8, 'What is the first step the security operations room must take upon receiving a report of an armed person inside the healthcare facility?', 'Announce Code Silver immediately over the overhead speaker system.', 'Rapidly verify the source of the report and the exact location of the armed person.', 'Collect detailed descriptions of the armed person including weapon type and number of injured.', 'Prevent patients, staff, and visitors from approaching the location of the armed person.', 1, '[\"UTIL_SLV_001_R01\"]', 1, '2026-05-06 08:04:31'),
(21, 8, 'As medical staff, what should you do when attempting to reach injured persons during a Code Silver incident?', 'Attempt to reach injured persons alone to provide immediate care.', 'Wait for the armed person to be neutralized before approaching injured persons.', 'Attempt to reach injured persons together with medical staff for safe transfer while maintaining the highest standards of protection and safety.', 'Focus solely on securing your own safety and avoid approaching injured persons until security clears the area.', 2, '[\"UTIL_SLV_001_R08\"]', 2, '2026-05-06 08:04:31'),
(22, 9, 'What is the first action the security operations room must take upon receiving a bomb threat report?', 'Immediately evacuate all patients and staff', 'Verify the source of the report and collect initial information', 'Notify specialized authorities through emergency numbers', 'Warn security personnel not to approach suspicious objects', 1, '[\"UTIL_BMB_001_R01\"]', 1, '2026-05-07 07:20:11'),
(23, 9, 'Who should be notified immediately after verifying a bomb threat report?', 'Facility leadership only', 'All hospital staff via overhead speaker', 'Relevant specialized authorities through approved emergency numbers', 'Security personnel on duty', 2, '[\"UTIL_BMB_001_R02\"]', 2, '2026-05-07 07:20:11'),
(24, 9, 'What instruction should be given to security personnel regarding suspicious objects before specialists arrive?', 'Attempt to move or open suspicious objects carefully', 'Isolate the area but do not move or examine suspicious objects', 'Ignore suspicious objects until evacuation is complete', 'Collect suspicious objects for evidence', 1, '[\"UTIL_BMB_001_R06\"]', 3, '2026-05-07 07:20:11'),
(25, 9, 'When should evacuation of patients, staff, and others be executed?', 'Immediately upon receiving the bomb threat report', 'Only after specialists have assessed the suspicious object', 'When directed by incident command based on threat severity and location', 'After notifying all hospital departments', 2, '[\"UTIL_BMB_001_R08\"]', 4, '2026-05-07 07:20:11'),
(26, 9, 'What is essential for specialists to do during the bomb threat incident to reduce risks?', 'Follow all directions and technical guidance issued by specialists responsible for this type of incident', 'Make independent decisions without consulting incident command', 'Focus only on evacuating patients', 'Delay communication until all information is confirmed', 0, '[\"UTIL_BMB_001_R03\"]', 5, '2026-05-07 07:20:11'),
(27, 10, 'What is the first action the security operations room must take upon receiving a report of a missing or abducted child?', 'Identify the exact location of the incident and begin an immediate response', 'Announce Code Pink over the overhead speaker system', 'Direct nursing staff to search the building', 'Request assistance from female security staff', 0, '[\"UTIL_PNK_001_R01\"]', 1, '2026-05-07 08:11:27'),
(28, 10, 'As female security staff, when are you specifically requested to assist during the search?', 'When inspection of female companions or visitors is required', 'When the child is found with a suspicious person', 'When the search expands outside the facility', 'When Code Pink is announced', 0, '[\"UTIL_PNK_001_R07\"]', 2, '2026-05-07 08:11:27'),
(29, 10, 'What should security personnel do if the missing child is found with a suspicious person?', 'Stop the person, verify their identity, and keep them under control until specialized security authorities arrive', 'Immediately release the person and continue searching', 'Call nursing staff to handle the situation', 'Expand the search to the outside surroundings', 0, '[\"UTIL_PNK_001_R08\"]', 3, '2026-05-07 08:11:27'),
(30, 10, 'What action is taken to alert staff throughout the facility about the missing child?', 'Announce Code Pink through the internal overhead speaker system and repeat the announcement', 'Send text messages to all staff', 'Post signs at all entrances', 'Call each department individually', 0, '[\"UTIL_PNK_001_R05\"]', 4, '2026-05-07 08:11:27'),
(31, 10, 'If the child is not found inside the facility after the initial search, what is the next step?', 'Expand the search to the outside surroundings and provide security authorities with all incident details and actions taken', 'Stop the search and wait for further instructions', 'Focus only on nursing staff to continue searching inside', 'Announce Code Pink again inside the facility', 0, '[\"UTIL_PNK_001_R09\"]', 5, '2026-05-07 08:11:27'),
(32, 11, 'What is the first action the security team must take upon receiving a report about an external disaster?', 'Verify the source, type, magnitude, location, and expected casualties of the disaster', 'Immediately announce Code Yellow over the overhead speaker system', 'Activate the facility external disaster emergency plan', 'Implement personal protective equipment measures', 0, '[\"UTIL_YLW_001_R01\"]', 1, '2026-05-07 08:16:59'),
(33, 11, 'After verification of the disaster report, what is the next step to prepare the facility for the external disaster?', 'Announce Code Yellow through the internal overhead speaker system and wireless devices to security teams', 'Immediately activate Code Red', 'Send all patients home to free up space', 'Notify the Hazmat Response Team to implement protective measures', 0, '[\"UTIL_YLW_001_R02\"]', 2, '2026-05-07 08:16:59'),
(34, 11, 'Which action should be taken to ensure the hospital is prepared internally after announcing Code Yellow?', 'Activate the facility external disaster emergency plan and implement relevant internal preparedness procedures', 'Immediately declare Code Red', 'Evacuate all non-essential staff', 'Request additional ambulances from external agencies', 0, '[\"UTIL_YLW_001_R03\"]', 3, '2026-05-07 08:16:59'),
(35, 11, 'Under what circumstance might the facility escalate from Code Yellow to Code Red during an external disaster response?', 'When the number of casualties exceeds the facility response capacity or an internal disaster such as a fire occurs', 'When the disaster is confirmed to be a biological threat', 'When the security team requests additional support', 'When the external disaster is declared over', 0, '[\"UTIL_YLW_001_R16\"]', 4, '2026-05-07 08:16:59'),
(36, 11, 'If the external disaster involves a biological, chemical, or radiological weapon, what must security personnel do?', 'Implement required personal protective equipment measures and comply with Hazmat Response Team instructions', 'Immediately evacuate the facility', 'Announce Code Red without further verification', 'Wait for instructions from the Infection Control Department', 0, '[\"UTIL_YLW_001_R13\"]', 5, '2026-05-07 08:16:59'),
(37, 12, 'What is the first step after receiving a report of a missing or abducted child in the hospital?', 'Identify the exact location of the incident and begin an immediate response', 'Announce Code Pink over the overhead speaker system', 'Search the outside surroundings of the building', 'Request assistance from female security staff', 0, '[\"UTIL_PNK_001_R01\"]', 1, '2026-05-07 08:36:19'),
(38, 12, 'During the search for the missing child, what should nursing staff and security personnel do?', 'Search carefully throughout the building and observe visitor behavior for suspicious movement', 'Immediately search the outside surroundings of the building', 'Only search the child’s last known location', 'Wait for specialized security authorities before starting the search', 0, '[\"UTIL_PNK_001_R02\"]', 2, '2026-05-07 08:36:19'),
(39, 12, 'How should the hospital alert staff throughout the facility about the missing child?', 'Announce Code Pink through the internal overhead speaker system and repeat the announcement', 'Send an email to all staff', 'Call each department individually', 'Post signs at the hospital entrances', 0, '[\"UTIL_PNK_001_R05\"]', 3, '2026-05-07 08:36:19'),
(40, 12, 'If the child is found with a suspicious person, what action should security personnel take?', 'Stop the person, verify their identity, and keep them under control until specialized security authorities arrive', 'Immediately release the person and child', 'Call the nursing staff to handle the situation', 'Ignore the situation and continue searching', 0, '[\"UTIL_PNK_001_R08\"]', 4, '2026-05-07 08:36:19'),
(41, 12, 'What should be done if the child is not found inside the facility after the initial search?', 'Expand the search to the outside surroundings and provide security authorities with all incident details and actions taken', 'Stop the search and wait for further instructions', 'Only search the parking lot', 'Announce Code Pink again and restart the internal search', 0, '[\"UTIL_PNK_001_R09\"]', 5, '2026-05-07 08:36:19'),
(42, 13, 'What is the first step the security operations room should take upon receiving a report of a chemical spill?', 'Announce Code Orange through the internal overhead speaker system.', 'Communicate directly with Civil Defense and the Hazmat Response Team.', 'Rapidly verify the source of the report and the exact incident location.', 'Prepare and submit a joint incident report with specialists.', 2, '[\"UTIL_HAZ_001_R01\"]', 1, '2026-05-07 08:42:46'),
(43, 13, 'How should the announcement of Code Orange be made within the facility?', 'Send a signal through wireless communication devices only.', 'Announce Code Orange once through the internal overhead speaker system.', 'Announce Code Orange through the internal overhead speaker system multiple times and send a wireless signal to security teams.', 'Communicate directly with Civil Defense and the Hazmat Response Team.', 2, '[\"UTIL_HAZ_001_R02\"]', 2, '2026-05-07 08:42:46'),
(44, 13, 'What must be ensured before allowing specialists access to the chemical spill incident site?', 'They have been briefed on the incident location.', 'They are wearing the designated clothing and protective equipment for chemical spill response.', 'They have communicated with Civil Defense.', 'They have submitted a joint incident report.', 1, '[\"UTIL_HAZ_001_R07\"]', 3, '2026-05-07 08:42:46'),
(45, 13, 'Who should Facility Leadership communicate with directly regarding the chemical spill incident?', 'Only the internal security teams.', 'Civil Defense and the Hazmat Response Team in the facility.', 'The hospital patients and visitors.', 'External media outlets.', 1, '[\"UTIL_HAZ_001_R03\"]', 4, '2026-05-07 08:42:46'),
(46, 13, 'What is the final reporting step after managing the hazardous material spill incident?', 'Prepare and submit a joint incident report with relevant specialists and Civil Defense to facility leadership.', 'Announce the end of Code Orange over the overhead system.', 'Comply with all directions issued by incident command.', 'Conduct a safety drill for future incidents.', 0, '[\"UTIL_HAZ_001_R10\"]', 5, '2026-05-07 08:42:46'),
(47, 14, 'What is the first step you should take upon learning that people are trapped in the elevator?', 'Record the names, time, location, number of trapped people, and their health status; provide support and reassurance.', 'Immediately call the engineer in charge for a follow-up inspection.', 'Switch off the elevator and label it as \'out of service\' on each floor.', 'Report and record findings after the issue is resolved.', 0, '[\"UTIL_ELV_001_R03\"]', 1, '2026-05-07 08:53:39'),
(48, 14, 'Who should you inform immediately after confirming trapped individuals in the elevator?', 'The Safety & Security Manager via extension 7777.', 'The maintenance technician on site.', 'The hospital administration office.', 'The elevator manufacturer.', 0, '[\"UTIL_ELV_001_R02\"]', 2, '2026-05-07 08:53:39'),
(49, 14, 'What action should be taken regarding the elevator if maintenance is ongoing during the failure?', 'Switch off the elevator and label it as \'out of service\' and under maintenance on each floor.', 'Keep the elevator running to avoid trapping more people.', 'Notify trapped individuals to remain calm without switching off the elevator.', 'Call the engineer to conduct a follow-up inspection immediately.', 0, '[\"UTIL_ELV_001_R07\"]', 3, '2026-05-07 08:53:39'),
(50, 14, 'What is the appropriate next step after informing the Safety & Security Manager about the elevator failure with trapped people?', 'Dispatch technicians to inspect the elevator, determine the cause, and prioritize releasing trapped people.', 'Call the engineer to conduct a follow-up inspection immediately.', 'Switch off the elevator and label it as \'out of service\'.', 'Report and record findings after the issue is resolved.', 0, '[\"UTIL_ELV_001_R04\"]', 4, '2026-05-07 08:53:39'),
(51, 14, 'What should be done after the elevator issue has been resolved and the system is back in operation?', 'Report and record findings and inform the Safety & Security Manager that the system returned to operation.', 'Immediately switch off the elevator and label it as \'out of service\'.', 'Call the engineer to start a new inspection.', 'Provide support and reassurance to trapped individuals again.', 0, '[\"UTIL_ELV_001_R08\"]', 5, '2026-05-07 08:53:39'),
(52, 15, 'What is the first step to take when a crowd begins to gather near the healthcare facility without official permission?', 'Allow the crowd to enter if they seem peaceful.', 'Prevent the crowd from entering the healthcare facility and its premises.', 'Call the media to report the gathering.', 'Ignore the crowd unless they become violent.', 1, '[\"UTIL_CROWD_001_R01\"]', 1, '2026-05-07 11:19:52'),
(53, 15, 'How should security personnel behave when interacting with a crowd to maintain order?', 'Use firm and loud commands to intimidate the crowd.', 'Demonstrate patience and calmness, avoid provocative behavior, and do not create fear by referencing past incidents.', 'Ignore the crowd and focus on other tasks.', 'Physically push the crowd back to disperse them quickly.', 1, '[\"UTIL_CROWD_001_R12\"]', 2, '2026-05-07 11:19:52'),
(54, 15, 'What should be done regarding security personnel deployment during a crowd gathering?', 'Deploy a minimal number of security personnel to avoid escalating the situation.', 'Deploy sufficient security personnel to manage the gathering and establish security perimeters when required.', 'Only deploy security personnel if the crowd becomes violent.', 'Allow volunteers to manage the crowd instead of security personnel.', 1, '[\"UTIL_CROWD_001_R03\"]', 3, '2026-05-07 11:19:52'),
(55, 15, 'If certain individuals are allowed entry to meet responsible officials inside the facility, what security measure should be taken?', 'Allow them to enter without any security accompaniment.', 'Assign an adequate number of security personnel to accompany these persons inside the facility.', 'Let the crowd escort them inside.', 'Request the individuals to wait outside until the crowd disperses.', 1, '[\"UTIL_CROWD_001_R08\"]', 4, '2026-05-07 11:19:52'),
(56, 15, 'What is the appropriate action to take after the crowd gathering situation has been managed?', 'Stop monitoring once the crowd starts to disperse.', 'Continue monitoring until the situation ends completely and ensure the crowd disperses from the surrounding area.', 'Immediately remove all security personnel to save resources.', 'Allow the crowd to remain near the facility as long as they are quiet.', 1, '[\"UTIL_CROWD_001_R10\"]', 5, '2026-05-07 11:19:52'),
(57, 16, 'What is the first step in notifying hospital personnel and security teams about the activation of a Code Yellow external disaster response?', 'Announce Code Yellow through the internal overhead speaker system and send a signal through wireless communication devices to security teams.', 'Directly contact ambulance command by phone to inform them of the disaster.', 'Send an email notification to all hospital staff.', 'Wait for the emergency departments to initiate communication.', 0, '[\"UTIL_YLW_001_R02\"]', 1, '2026-05-07 11:32:18'),
(58, 16, 'After announcing Code Yellow, what is the next critical action to take in managing the hospital\'s response?', 'Activate the facility external disaster emergency plan and implement relevant internal preparedness procedures.', 'Immediately declare Code Red to escalate the response.', 'Begin evacuating all patients from the hospital.', 'Request additional ambulances from external agencies.', 0, '[\"UTIL_YLW_001_R03\"]', 2, '2026-05-07 11:32:18'),
(59, 16, 'Which departments or units should the Planning and Preparedness Unit coordinate with to raise readiness and preparedness for security personnel in the receiving area during an external disaster?', 'Ambulance command, emergency departments, and the planning and emergency preparedness unit.', 'Infection Control Department and Hazmat Response Team only.', 'Hospital administration and finance departments.', 'Patient transport services and cafeteria staff.', 0, '[\"UTIL_YLW_001_R04\"]', 3, '2026-05-07 11:32:18'),
(60, 16, 'Under what circumstances might the hospital escalate from Code Yellow to Code Red during an external disaster response?', 'When the number of casualties exceeds the facility response capacity or when an internal disaster such as a fire occurs.', 'When the external disaster is declared over by local authorities.', 'When security personnel complete their shift changes.', 'When the Infection Control Department issues new guidelines.', 0, '[\"UTIL_YLW_001_R16\"]', 4, '2026-05-07 11:32:18'),
(61, 16, 'If the external disaster involves a biological, chemical, or radiological threat, what must security personnel do according to the pre-activated response plans?', 'Implement required personal protective equipment measures and comply with instructions issued by the Hazmat Response Team.', 'Follow standard security protocols without additional protective measures.', 'Coordinate only with ambulance command for patient transport.', 'Wait for instructions from hospital administration before acting.', 0, '[\"UTIL_YLW_001_R13\"]', 5, '2026-05-07 11:32:18'),
(62, 17, 'What is the first action the security operations room must take upon receiving a report of a chemical spill?', 'Immediately announce Code Orange over the overhead speaker system.', 'Rapidly verify the source of the report and the exact incident location.', 'Send security staff directly to the incident site without delay.', 'Contact the hospital administration for further instructions.', 1, '[\"UTIL_HAZ_001_R01\"]', 1, '2026-05-07 11:44:32'),
(63, 17, 'How should security personnel announce the Code Orange alert within the hospital?', 'Send a single wireless message to the emergency response teams.', 'Announce Code Orange once over the overhead speaker system.', 'Announce Code Orange several times over the overhead speaker system and send a wireless signal to security teams.', 'Notify only the Hazmat Response Team via phone call.', 2, '[\"UTIL_HAZ_001_R02\"]', 2, '2026-05-07 11:44:32'),
(64, 17, 'What safety measures should security staff take when securing the hazardous spill site?', 'Remain in the affected area as long as possible to monitor the situation.', 'Avoid direct exposure to toxic emissions, use personal protective equipment, and rotate with other staff.', 'Wait for the Hazmat Response Team to arrive before taking any action.', 'Only wear standard security uniforms without additional protective gear.', 1, '[\"UTIL_HAZ_001_R04\", \"UTIL_HAZ_001_R05\"]', 3, '2026-05-07 11:44:32'),
(65, 18, 'What is the correct initial communication step to announce a fire emergency within the hospital?', 'Announce Code Red through the internal overhead speaker system and repeat the announcement several times, while also sending a signal through wireless communication devices to the security teams assigned for emergency response.', 'Send an email to all hospital staff detailing the fire incident.', 'Wait for the fire to be confirmed by the facility leadership before making any announcements.', 'Call the National Center for Emergency and Health Crisis Management first before any internal announcements.', 0, '[\"UTIL_FIRE_001_R02\"]', 1, '2026-05-07 11:52:18'),
(66, 18, 'Who should Civil Defense communicate with directly regarding the fire incident?', 'The facility firefighting unit and Civil Defense themselves.', 'Only the hospital administration.', 'External media outlets to inform the public.', 'The National Center for Emergency and Health Crisis Management exclusively.', 0, '[\"UTIL_FIRE_001_R03\"]', 2, '2026-05-07 11:52:18'),
(67, 18, 'What is the final reporting step after managing the fire incident?', 'Prepare and submit a joint incident report with the relevant specialists in the facility and Civil Defense to the facility leadership.', 'Only notify the National Center for Emergency and Health Crisis Management without internal reporting.', 'Send a brief verbal update to the security staff without documentation.', 'Wait for the fire to be fully extinguished before reporting.', 0, '[\"UTIL_FIRE_001_R09\"]', 3, '2026-05-07 11:52:18'),
(68, 19, 'What is your first step upon learning that people are trapped in the elevator?', 'Record the names, time, location, number of trapped people, and their health status; provide support and reassurance until help arrives.', 'Immediately switch off the elevator and label it as \'out of service\' on each floor.', 'Call the Safety & Security Manager through extension 7777.', 'Dispatch technicians to inspect and determine the cause of the failure.', 0, '[\"UTIL_ELV_001_R03\"]', 1, '2026-05-07 12:01:29'),
(69, 19, 'After confirming the trapped passengers\' status, what action should you take next?', 'Switch off the elevator and label it as \'out of service\' on each floor to prevent use during maintenance.', 'Call the engineer in charge to conduct a follow-up inspection.', 'Dispatch technicians to inspect the elevator, determine the cause, and prioritize releasing trapped people.', 'Report and record findings and inform the Safety & Security Manager that the system returned to operation.', 2, '[\"UTIL_ELV_001_R04\"]', 2, '2026-05-07 12:01:29'),
(70, 19, 'Once the elevator issue is resolved and the system is operational again, what is the appropriate final step?', 'Switch off the elevator and label it as \'out of service\' until maintenance is completed.', 'Inform the Safety & Security Manager through extension 7777 about the issue.', 'Report and record findings and inform the Safety & Security Manager that the system returned to operation.', 'Call the engineer in charge to conduct a follow-up inspection.', 2, '[\"UTIL_ELV_001_R08\"]', 3, '2026-05-07 12:01:29'),
(71, 20, 'What is your immediate action upon being notified of trapped people in the elevator?', 'Record names, time, location, inquire about number and health status of trapped people, and provide reassurance until help arrives.', 'Immediately switch off the elevator and label it out of service on each floor.', 'Call the Safety & Security Manager through extension 7777.', 'Dispatch technicians to inspect and fix the elevator.', 0, '[\"UTIL_ELV_001_R03\"]', 1, '2026-05-07 12:07:33'),
(72, 20, 'After being informed of the elevator failure, what is the next step you should take to address the technical issue?', 'Call the engineer in charge to conduct follow-up inspection and detect the cause of the issue.', 'Dispatch technicians to inspect, determine the cause, and prioritize releasing trapped people.', 'Switch off the elevator and label it as out of service on each floor.', 'Inform the Safety & Security Manager through extension 7777.', 1, '[\"UTIL_ELV_001_R04\"]', 2, '2026-05-07 12:07:33'),
(73, 20, 'If elevator maintenance is ongoing during the failure, what precaution must be taken to prevent further use of the elevator?', 'Switch off the elevator and label it as \'out of service\' and under maintenance on each floor.', 'Immediately call the Safety & Security Manager.', 'Record the names and health status of trapped people.', 'Dispatch technicians to inspect the elevator.', 0, '[\"UTIL_ELV_001_R07\"]', 3, '2026-05-07 12:07:33'),
(74, 20, 'Once the elevator issue is resolved and the system is operational again, what is your responsibility?', 'Report and record findings and inform the Safety & Security Manager that the system returned to operation.', 'Immediately dispatch technicians to inspect the elevator again.', 'Switch off the elevator and label it as out of service.', 'Call the trapped people to confirm their health status.', 0, '[\"UTIL_ELV_001_R08\"]', 4, '2026-05-07 12:07:33'),
(75, 21, 'What is the first step you should take upon noticing the large crowd gathering?', 'Deploy sufficient security personnel to manage the gathering and establish security perimeters.', 'Immediately disperse the crowd using loud verbal commands.', 'Allow the crowd to enter the facility without restrictions.', 'Contact hospital medical staff to assist with crowd control.', 0, '[\"UTIL_CROWD_001_R03\"]', 1, '2026-05-07 12:19:33'),
(76, 21, 'How should security personnel behave when interacting with the crowd to avoid escalating tensions?', 'Demonstrate patience and calmness, show good conduct, avoid provocative expressions, and avoid creating fear by referencing previous incidents.', 'Use firm and loud verbal warnings to assert authority.', 'Ignore the crowd and focus on other tasks.', 'Reference previous incidents to warn the crowd about consequences.', 0, '[\"UTIL_CROWD_001_R12\"]', 2, '2026-05-07 12:19:33'),
(77, 21, 'What information should be collected and reported to the security administration regarding the crowd?', 'Count the number of individuals involved and classify them according to the security situation.', 'Only report if the crowd becomes violent.', 'Report the names of individuals in the crowd.', 'Ignore the crowd size and focus on internal hospital security.', 0, '[\"UTIL_CROWD_001_R07\"]', 3, '2026-05-07 12:19:33'),
(78, 21, 'How should communication be handled during the incident?', 'Maintain continuous coordination and communication with specialized security authorities throughout the incident.', 'Only communicate with hospital leadership after the incident is resolved.', 'Use informal channels to quickly share information.', 'Limit communication to internal security staff only.', 0, '[\"UTIL_CROWD_001_R06\"]', 4, '2026-05-07 12:19:33'),
(79, 21, 'If certain individuals are allowed entry to meet responsible officials inside the facility, what should be done?', 'Assign an adequate number of security personnel to accompany those individuals.', 'Allow them to enter unaccompanied to avoid delays.', 'Request the crowd to escort them inside.', 'Deny entry to all individuals until the crowd disperses.', 0, '[\"UTIL_CROWD_001_R08\"]', 5, '2026-05-07 12:19:33');

